import { Category, Document, Stats, ActivityLog } from '../types';
import { INITIAL_CATEGORIES, INITIAL_DOCUMENTS } from '../constants';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  USER: 'sp_user_session',
};

export const storageService = {
  // Categories
  getCategories: (): Category[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    return data ? JSON.parse(data) : INITIAL_CATEGORIES;
  },
  saveCategories: (cats: Category[]) => {
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(cats));
  },

  // Documents
  getDocuments: (): Document[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    return data ? JSON.parse(data) : INITIAL_DOCUMENTS;
  },
  saveDocuments: (docs: Document[]) => {
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
  },
  incrementDownload: (docId: string) => {
    const docs = storageService.getDocuments();
    const updated = docs.map(d => d.id === docId ? { ...d, downloads: d.downloads + 1 } : d);
    storageService.saveDocuments(updated);
    storageService.updateStats(0, 1);
  },

  // Stats
  getStats: (): Stats => {
    const data = localStorage.getItem(KEYS.STATS);
    if (!data) {
      return { totalVisits: 100, totalDownloads: 209, categoryPopularity: {} };
    }
    return JSON.parse(data);
  },
  updateStats: (visits: number, downloads: number) => {
    const stats = storageService.getStats();
    stats.totalVisits += visits;
    stats.totalDownloads += downloads;
    localStorage.setItem(KEYS.STATS, JSON.stringify(stats));
  },

  // Logs
  getLogs: (): ActivityLog[] => {
    const data = localStorage.getItem(KEYS.LOGS);
    return data ? JSON.parse(data) : [];
  },
  addLog: (action: string, details: string) => {
    const logs = storageService.getLogs();
    logs.unshift({
      id: Math.random().toString(36).substr(2, 9),
      action,
      details,
      timestamp: new Date().toISOString()
    });
    localStorage.setItem(KEYS.LOGS, JSON.stringify(logs.slice(0, 50)));
  },

  // User session
  getUser: () => {
    const data = localStorage.getItem(KEYS.USER);
    return data ? JSON.parse(data) : null;
  },
  setUser: (email: string) => {
    localStorage.setItem(KEYS.USER, JSON.stringify({ email, isValidated: true }));
  }
};

import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const stars = Array.from({ length: 200 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      size: Math.random() * 1.5,
      opacity: Math.random(),
      speed: Math.random() * 0.01 + 0.005
    }));

    const draw = (time: number) => {
      ctx.fillStyle = '#0a192f';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Stars
      ctx.fillStyle = '#e6f1ff';
      stars.forEach(star => {
        star.opacity += star.speed;
        if (star.opacity > 1 || star.opacity < 0) star.speed *= -1;
        ctx.globalAlpha = Math.max(0, star.opacity);
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fill();
      });

      // Aurora effect (simplified with radial gradients)
      ctx.globalAlpha = 0.05;
      const gradient = ctx.createRadialGradient(
        canvas.width * 0.5 + Math.sin(time * 0.0005) * 100,
        canvas.height * 0.2,
        0,
        canvas.width * 0.5,
        canvas.height * 0.2,
        canvas.width * 0.6
      );
      gradient.addColorStop(0, '#00d4ff');
      gradient.addColorStop(0.5, '#7b4dff');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.globalAlpha = 1;
      animationFrameId = requestAnimationFrame(draw);
    };

    animationFrameId = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1]" />;
};

export default AuroraBackground;

