  useEffect(() => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setUserSession(storageService.getUser());
    storageService.updateStats(1, 0); // Log visit
  }, []);

  const filteredDocs = useMemo(() => {
    return documents.filter(doc => {
      const matchesSearch = doc.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            doc.description.toLowerCase().includes(searchQuery.toLowerCase());

      let matchesCat = true;
      if (selectedChildCat) {
        matchesCat = doc.categoryId === selectedChildCat;
      } else if (selectedParentCat) {
        const childCatIds = categories.filter(c => c.parentId === selectedParentCat).map(c => c.id);
        matchesCat = childCatIds.includes(doc.categoryId);
      }

      return matchesSearch && matchesCat;
    });
  }, [documents, searchQuery, selectedParentCat, selectedChildCat, categories]);

  const handleDownloadRequest = (doc: Document) => {
    if (userSession?.isValidated) {
      window.open(doc.githubUrl, '_blank');
      storageService.incrementDownload(doc.id);
      setDocuments(storageService.getDocuments());
    } else {
      setPendingDoc(doc);
      setShowEmailModal(true);
    }
  };

  const sendEmailCode = () => {
    if (!emailInput.includes('@')) return;
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedCode(code);
    setShowCodeStep(true);
    // Simulate EmailJS
    console.log(`[POLARIS SIMULATION] Sending code ${code} to ${emailInput}`);
    alert(`Un code de validation a été envoyé à ${emailInput}. (Simulé: ${code})`);
  };

  const validateCode = () => {
    if (codeInput === generatedCode || codeInput === '123456') { // Master code for testing
      storageService.setUser(emailInput);
      setUserSession({ email: emailInput, isValidated: true });
      setShowEmailModal(false);
      if (pendingDoc) {
        window.open(pendingDoc.githubUrl, '_blank');
        storageService.incrementDownload(pendingDoc.id);
        setDocuments(storageService.getDocuments());
      }
    } else {
      alert("Code invalide. Réessayez.");
    }
  };

  const handleAdminLogin = () => {
    if (adminUsername === ADMIN_CREDENTIALS.username && adminPassword === ADMIN_CREDENTIALS.password) {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      storageService.addLog('Admin Login', `L'administrateur ${adminUsername} s'est connecté.`);
    } else {
      alert("Identifiants incorrects.");
    }
  };

  return (
