import { Category, Document, Stats, ActivityLog, VisitorActivity } from '../types';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'activity' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [visitorActivity, setVisitorActivity] = useState<VisitorActivity[]>([]);
  const [logs, setLogs] = useState<ActivityLog[]>([]);

  // New Category Form
  const [showCatForm, setShowCatForm] = useState(false);
  const [newCatName, setNewCatName] = useState('');
  const [selectedParentId, setSelectedParentId] = useState<string | null>(null);

  // New Doc Form
  const [showDocForm, setShowDocForm] = useState(false);
  const [newDoc, setNewDoc] = useState({ title: '', description: '', githubUrl: '', categoryId: '' });

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setVisitorActivity(storageService.getVisitorActivities());
    setLogs(storageService.getLogs());
  };

  useEffect(() => {
    refresh();
    const interval = setInterval(refresh, 5000);
    return () => clearInterval(interval);
  }, []);

  const handleAddCategory = () => {
    if (!newCatName) return;
    storageService.saveCategory(newCatName, selectedParentId);
    setNewCatName('');
    setShowCatForm(false);
    refresh();
  };

  const handleAddDocument = () => {
    if (!newDoc.title || !newDoc.categoryId || !newDoc.githubUrl) return;
    storageService.addDocument(newDoc);
    setShowDocForm(false);
    setNewDoc({ title: '', description: '', githubUrl: '', categoryId: '' });
    refresh();
  };

  return (
    <div className="bg-slate-900/90 rounded-3xl border border-white/10 overflow-hidden shadow-2xl backdrop-blur-2xl">
      <div className="flex bg-black/20 p-2 gap-2">
        {(['tree', 'activity', 'logs'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 py-3 px-6 rounded-2xl text-xs font-black uppercase tracking-[0.2em] transition-all ${
              activeTab === tab ? 'bg-cyan-500 text-slate-950 shadow-lg shadow-cyan-500/20' : 'text-white/40 hover:text-white hover:bg-white/5'
            }`}
          >
            {tab === 'tree' ? 'Structure' : tab === 'activity' ? 'Live Flux' : 'Journal'}
          </button>
        ))}
      </div>

      <div className="p-8">
        {activeTab === 'tree' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-black text-white italic">GESTION DE L'ARBORESCENCE</h3>
              <button 
                onClick={() => { setSelectedParentId(null); setShowCatForm(true); }}
                className="bg-white text-slate-950 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-colors"
              >
                + Créer un Arbre
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {categories.filter(c => !c.parentId).map(root => (
                <div key={root.id} className="bg-white/5 border border-white/10 rounded-2xl p-6 hover:border-cyan-500/50 transition-all">
                  <div className="flex justify-between items-center mb-4">
                    <span className="text-cyan-400 font-black uppercase text-xs">{root.name}</span>
                    <button 
                      onClick={() => { setSelectedParentId(root.id); setShowCatForm(true); }}
                      className="text-[10px] text-white/20 hover:text-white"
                    >
                      + Branche
                    </button>
                  </div>
                  <div className="space-y-2 ml-4 border-l border-white/10 pl-4">
                    {categories.filter(c => c.parentId === root.id).map(child => (
                      <div key={child.id} className="group">
                        <div className="flex justify-between items-center py-1">
                          <span className="text-white/60 text-sm font-medium">{child.name}</span>
                          <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                              onClick={() => { 
                                setNewDoc({...newDoc, categoryId: child.id});
                                setShowDocForm(true);
                              }}
                              className="text-cyan-400 text-[10px] font-bold"
                            >
                              + PDF
                            </button>
                            <button onClick={() => storageService.deleteCategory(child.id)} className="text-red-400 text-[10px]">✕</button>
                          </div>
                        </div>
                        {/* Recursive display would go here for deeper trees */}
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'activity' && (
          <div className="space-y-6 animate-in fade-in duration-500">
             <div className="flex items-center gap-3 mb-6">
               <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
               <h3 className="text-xl font-black text-white italic">FLUX D'EXPLORATION EN DIRECT</h3>
             </div>
             <div className="space-y-3">
               {visitorActivity.map(act => (
                 <div key={act.id} className="bg-black/40 border border-white/5 rounded-xl p-4 flex justify-between items-center group hover:border-cyan-500/30">
                   <div className="flex items-center gap-4">
                     <div className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center font-mono text-[10px] text-cyan-400">
                       USR
                     </div>
                     <div>
                       <p className="text-white/80 text-sm font-bold tracking-tight">{act.path}</p>
                       <p className="text-[10px] text-white/20 font-mono">{new Date(act.timestamp).toLocaleTimeString()}</p>
                     </div>
                   </div>
                   <div className="text-[10px] text-cyan-400/50 uppercase font-black tracking-widest">En Exploration</div>
                 </div>
               ))}
               {visitorActivity.length === 0 && <p className="text-center py-20 text-white/20 italic">Aucune activité pour le moment...</p>}
             </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h3 className="text-xl font-black text-white mb-6 italic">JOURNAL DES OPÉRATIONS</h3>
            <div className="font-mono text-[11px] space-y-2 bg-black/40 p-6 rounded-2xl border border-white/5">
              {logs.map(log => (
                <div key={log.id} className="flex gap-4">
                  <span className="text-white/20">[{log.timestamp}]</span>
                  <span className="text-cyan-400 font-bold uppercase">{log.action}:</span>
                  <span className="text-white/60">{log.details}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Category Modal */}
      {showCatForm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 backdrop-blur-2xl">
          <div className="absolute inset-0 bg-black/80" onClick={() => setShowCatForm(false)}></div>
          <div className="bg-slate-900 border border-white/10 rounded-3xl p-10 max-w-sm w-full relative z-10 shadow-2xl">
            <h4 className="text-xl font-black text-white mb-6 italic">NOUVELLE BRANCHE</h4>
            <input 
              type="text" 
              placeholder="Nom de la catégorie" 
              value={newCatName}
              onChange={(e) => setNewCatName(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white mb-6 focus:border-cyan-400 outline-none"
            />
            <button onClick={handleAddCategory} className="w-full bg-cyan-500 text-slate-900 font-black py-4 rounded-2xl uppercase tracking-widest">Valider</button>
          </div>
        </div>
      )}

      {/* Doc Modal */}
      {showDocForm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 backdrop-blur-2xl">
          <div className="absolute inset-0 bg-black/80" onClick={() => setShowDocForm(false)}></div>
          <div className="bg-slate-900 border border-white/10 rounded-3xl p-10 max-w-md w-full relative z-10 shadow-2xl">
            <h4 className="text-xl font-black text-white mb-6 italic">EXPOSER UN DOCUMENT</h4>
            <div className="space-y-4 mb-8">
              <input 
                type="text" 
                placeholder="Titre" 
                value={newDoc.title}
                onChange={(e) => setNewDoc({...newDoc, title: e.target.value})}
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-cyan-400 outline-none"
              />
              <textarea 
                placeholder="Description" 
                value={newDoc.description}
                onChange={(e) => setNewDoc({...newDoc, description: e.target.value})}
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-cyan-400 outline-none h-24"
              />
              <input 
                type="text" 
                placeholder="URL Pointeur (Téléphone/Cloud)" 
                value={newDoc.githubUrl}
                onChange={(e) => setNewDoc({...newDoc, githubUrl: e.target.value})}
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-cyan-400 outline-none"
              />
            </div>
            <button onClick={handleAddDocument} className="w-full bg-cyan-500 text-slate-900 font-black py-4 rounded-2xl uppercase tracking-widest">Publier l'Alerte</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground';
import DocumentCard from './components/DocumentCard';
import AdminDashboard from './components/AdminDashboard';
import { storageService } from './services/storageService';
import { Category, Document, UserSession } from './types';
import { ADMIN_CREDENTIALS } from './constants';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Tree Navigation State
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);

  // Auth & UI States
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [userSession, setUserSession] = useState<UserSession | null>(null);
  const [showEmailModal, setShowEmailModal] = useState(false);
  const [pendingDoc, setPendingDoc] = useState<Document | null>(null);

  // Notification Alert
  const [showNewAlert, setShowNewAlert] = useState(false);

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    if (storageService.getNewPostFlag()) {
      setShowNewAlert(true);
    }
  };

  useEffect(() => {
    refreshData();
    setUserSession(storageService.getUser());
    storageService.updateStats(1, 0);
  }, [isAdminMode]);

  // Navigate through categories
  const navigateTo = (cat: Category | null) => {
    if (!cat) {
      setNavigationPath([]);
      storageService.trackMovement("Accueil");
    } else {
      const path = [...navigationPath, cat];
      setNavigationPath(path);
      storageService.trackMovement(path.map(c => c.name).join(" > "));
    }
  };

  const goBack = (index: number) => {
    const newPath = navigationPath.slice(0, index + 1);
    setNavigationPath(newPath);
    storageService.trackMovement(newPath.map(c => c.name).join(" > "));
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath]);

  const currentLevelDocuments = useMemo(() => {
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath]);

  const handleDownload = (doc: Document) => {
    if (userSession?.isValidated) {
      window.open(doc.githubUrl, '_blank');
      storageService.incrementDownload(doc.id);
      refreshData();
    } else {
      setPendingDoc(doc);
      setShowEmailModal(true);
    }
  };

  const dismissAlert = () => {
    setShowNewAlert(false);
    storageService.acknowledgeNewPosts();
  };

  return (
    <div className="min-h-screen relative pb-32 text-slate-100">
      <AuroraBackground />

      {/* Global New Post Alert */}
      {showNewAlert && !isAdminMode && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[200] bg-cyan-500 text-slate-950 px-8 py-4 rounded-full shadow-[0_0_40px_rgba(0,212,255,0.4)] flex items-center gap-4 animate-in slide-in-from-top-12 duration-500">
          <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center animate-bounce">
            <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a6 6 0 00-6 6v3.586l-.707.707A1 1 0 004 14h12a1 1 0 00.707-1.707L16 11.586V8a6 6 0 00-6-6zM10 18a3 3 0 01-3-3h6a3 3 0 01-3 3z" /></svg>
          </div>
          <span className="font-black uppercase text-xs tracking-tighter">Léon vient de poster de nouveaux trésors !</span>
          <button onClick={dismissAlert} className="ml-4 hover:scale-110 transition-transform">✕</button>
        </div>
      )}

      {/* Header */}
      <header className="container mx-auto px-6 py-12 flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="flex items-center gap-4 cursor-pointer" onClick={() => navigateTo(null)}>
          <div className="w-14 h-14 bg-cyan-500 rounded-2xl flex items-center justify-center shadow-2xl hover:rotate-6 transition-transform">
            <svg className="w-9 h-9 text-slate-950" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">SUCCESS<span className="text-cyan-400">POLARIS</span></h1>
            <p className="text-[10px] uppercase tracking-[0.4em] text-white/30 font-bold">L'Excellence par Léon</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <input 
            type="text" 
            placeholder="Rechercher..." 
            className="bg-white/5 border border-white/10 rounded-2xl px-6 py-3 text-sm focus:border-cyan-400 outline-none w-64 backdrop-blur-xl"
          />
          {isAdminMode && (
             <button 
                onClick={() => setIsAdminMode(false)}
                className="text-[10px] font-black uppercase text-white/40 border border-white/10 px-4 py-2 rounded-lg hover:text-white"
             >Quitter Admin</button>
          )}
        </div>
      </header>

      {/* Main Experience */}
      <main className="container mx-auto px-6">
        {isAdminMode ? (
          <AdminDashboard />
        ) : (
          <div className="space-y-12">
            {/* Breadcrumbs Navigation */}
            <div className="flex items-center gap-3 bg-white/5 p-4 rounded-2xl border border-white/10 backdrop-blur-md">
              <button onClick={() => navigateTo(null)} className="text-white/40 hover:text-cyan-400 text-xs font-bold uppercase tracking-widest">RACINE</button>
              {navigationPath.map((cat, i) => (
                <React.Fragment key={cat.id}>
                  <span className="text-white/10">/</span>
                  <button 
                    onClick={() => goBack(i)}
                    className="text-cyan-400 text-xs font-black uppercase tracking-widest hover:text-white"
                  >{cat.name}</button>
                </React.Fragment>
              ))}
            </div>

            {/* Content Explorer */}
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
              {/* Branches Column */}
              <div className="lg:col-span-1 space-y-4">
                <h3 className="text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-6 flex items-center gap-4">
                  <span className="w-10 h-[1px] bg-white/10"></span> EXPLORATION
                </h3>
                {currentLevelCategories.length > 0 ? (
                  <div className="space-y-3">
                    {currentLevelCategories.map(cat => (
                      <button 
                        key={cat.id}
                        onClick={() => navigateTo(cat)}
                        className="w-full flex items-center justify-between p-6 bg-white/5 border border-transparent hover:border-cyan-500/30 hover:bg-white/10 rounded-2xl transition-all group"
                      >
                        <span className="text-sm font-bold text-white/60 group-hover:text-white">{cat.name}</span>
                        <svg className="w-5 h-5 text-white/20 group-hover:text-cyan-400 transition-transform group-hover:translate-x-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                      </button>
                    ))}
                  </div>
                ) : (
                  <p className="text-white/20 text-xs italic">C'est la fin de cette branche.</p>
                )}
              </div>

              {/* Documents Grid */}
              <div className="lg:col-span-3 space-y-6">
                 <h3 className="text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-6 flex items-center gap-4">
                  <span className="w-10 h-[1px] bg-white/10"></span> TRÉSORS TROUVÉS
                </h3>
                {currentLevelDocuments.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in duration-700">
                    {currentLevelDocuments.map(doc => (
                      <DocumentCard key={doc.id} doc={doc} onDownload={handleDownload} />
                    ))}
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center py-32 bg-white/5 rounded-[3rem] border border-dashed border-white/10">
                    <p className="text-white/20 text-sm font-medium">Naviguez dans les branches pour trouver des documents.</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="fixed bottom-0 left-0 w-full p-8 bg-slate-950/80 backdrop-blur-2xl border-t border-white/5 flex flex-col md:flex-row items-center justify-between z-50">
        <p className="text-[10px] text-white/20 font-black uppercase tracking-[0.5em]">Polaris Core v2.0</p>
        <button 
          onClick={() => setShowAdminLogin(true)}
          className="text-cyan-400/30 hover:text-cyan-400 text-[10px] font-black uppercase tracking-widest transition-colors"
        >Accès Gardien (Léon)</button>
      </footer>

      {/* Auth Modal */}
      {showAdminLogin && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 backdrop-blur-3xl">
          <div className="absolute inset-0 bg-black/90" onClick={() => setShowAdminLogin(false)}></div>
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] p-12 max-w-md w-full relative z-10 shadow-2xl">
            <h3 className="text-4xl font-black text-white italic tracking-tighter mb-10 text-center">SESSION ADMIN</h3>
            <div className="space-y-6 mb-10">
              <input 
                type="text" 
                placeholder="Identifiant" 
                value={adminUsername}
                onChange={(e) => setAdminUsername(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none focus:border-cyan-400"
              />
              <input 
                type="password" 
                placeholder="Clé de Sécurité" 
                value={adminPassword}
                onChange={(e) => setAdminPassword(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none focus:border-cyan-400"
              />
            </div>
            <button 
              onClick={() => {
                if (adminUsername === ADMIN_CREDENTIALS.username && adminPassword === ADMIN_CREDENTIALS.password) {
                  setIsAdminMode(true);
                  setShowAdminLogin(false);
                }
              }}
              className="w-full bg-white text-slate-950 font-black py-5 rounded-3xl uppercase tracking-widest shadow-2xl hover:bg-cyan-400 transition-colors"
            >Initier Connexion</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { Category, Document, Stats, ActivityLog, VisitorActivity } from '../types';
import { INITIAL_CATEGORIES, INITIAL_DOCUMENTS } from '../constants';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  USER: 'sp_user_session',
  LAST_DOC_COUNT: 'sp_last_count',
  ACTIVITY: 'sp_visitor_activity'
};

export const storageService = {
  // Categories
  getCategories: (): Category[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    return data ? JSON.parse(data) : INITIAL_CATEGORIES;
  },
  saveCategory: (name: string, parentId: string | null) => {
    const cats = storageService.getCategories();
    const newCat = { id: `cat-${Date.now()}`, name, parentId };
    storageService.saveCategories([...cats, newCat]);
    storageService.addLog('Structure', `Nouvelle branche créée : ${name}`);
    return newCat;
  },
  saveCategories: (cats: Category[]) => {
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(cats));
  },
  deleteCategory: (id: string) => {
    const cats = storageService.getCategories().filter(c => c.id !== id);
    const docs = storageService.getDocuments().filter(d => d.categoryId !== id);
    storageService.saveCategories(cats);
    storageService.saveDocuments(docs);
  },

  // Documents
  getDocuments: (): Document[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    return data ? JSON.parse(data) : INITIAL_DOCUMENTS;
  },
  saveDocuments: (docs: Document[]) => {
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
  },
  addDocument: (doc: Omit<Document, 'id' | 'downloads' | 'dateAdded'>) => {
    const docs = storageService.getDocuments();
    const newDoc = {
      ...doc,
      id: `doc-${Date.now()}`,
      downloads: 0,
      dateAdded: new Date().toISOString()
    };
    storageService.saveDocuments([newDoc, ...docs]);
    storageService.addLog('Publication', `Document exposé : ${doc.title}`);
  },

  // Missing method fix: Increments the download count for a specific document and updates global stats
  incrementDownload: (id: string) => {
    const docs = storageService.getDocuments();
    const docIndex = docs.findIndex(d => d.id === id);
    if (docIndex > -1) {
      docs[docIndex].downloads += 1;
      storageService.saveDocuments(docs);
      storageService.updateStats(0, 1);
      storageService.addLog('Téléchargement', `Fichier récupéré : ${docs[docIndex].title}`);
    }
  },

  // Visitor Tracking
  trackMovement: (path: string) => {
    const activities = storageService.getVisitorActivities();
    const newAct = {
      id: Math.random().toString(36).substr(2, 9),
      path,
      timestamp: new Date().toISOString()
    };
    localStorage.setItem(KEYS.ACTIVITY, JSON.stringify([newAct, ...activities].slice(0, 20)));
  },
  getVisitorActivities: (): VisitorActivity[] => {
    const data = localStorage.getItem(KEYS.ACTIVITY);
    return data ? JSON.parse(data) : [];
  },

  // Notifications
  getNewPostFlag: () => {
    const count = storageService.getDocuments().length;
    const lastCount = Number(localStorage.getItem(KEYS.LAST_DOC_COUNT) || count);
    return count > lastCount;
  },
  acknowledgeNewPosts: () => {
    localStorage.setItem(KEYS.LAST_DOC_COUNT, storageService.getDocuments().length.toString());
  },

  // Stats & Logs
  getStats: (): Stats => {
    const data = localStorage.getItem(KEYS.STATS);
    return data ? JSON.parse(data) : { totalVisits: 0, totalDownloads: 0 };
  },
  updateStats: (v: number, d: number) => {
    const s = storageService.getStats();
    localStorage.setItem(KEYS.STATS, JSON.stringify({ totalVisits: s.totalVisits + v, totalDownloads: s.totalDownloads + d }));
  },
  getLogs: (): ActivityLog[] => {
    const data = localStorage.getItem(KEYS.LOGS);
    return data ? JSON.parse(data) : [];
  },
  addLog: (action: string, details: string) => {
    const logs = storageService.getLogs();
    const newLog = { id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.LOGS, JSON.stringify([newLog, ...logs].slice(0, 50)));
  },
  getUser: () => JSON.parse(localStorage.getItem(KEYS.USER) || 'null'),
  setUser: (email: string) => localStorage.setItem(KEYS.USER, JSON.stringify({ email, isValidated: true }))
};

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService';
import { Category, Document, Stats, ActivityLog, VisitorActivity } from '../types';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'live' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [visitorActivity, setVisitorActivity] = useState<VisitorActivity[]>([]);
  const [logs, setLogs] = useState<ActivityLog[]>([]);

  // States for forms
  const [newRootName, setNewRootName] = useState('');
  const [showDocModal, setShowDocModal] = useState<{show: boolean, catId: string}>({ show: false, catId: '' });
  const [newDoc, setNewDoc] = useState({ title: '', description: '', githubUrl: '' });

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setVisitorActivity(storageService.getVisitorActivities());
    setLogs(storageService.getLogs());
  };

  useEffect(() => {
    refresh();
    const interval = setInterval(refresh, 3000); // Rafraîchissement rapide pour le "Live"
    return () => clearInterval(interval);
  }, []);

  const handleCreateRoot = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRootName.trim()) return;
    storageService.saveCategory(newRootName, null);
    setNewRootName('');
    refresh();
  };

  const handleAddBranch = (parentId: string) => {
    const name = prompt("Nom de la nouvelle branche (sous-catégorie) :");
    if (name) {
      storageService.saveCategory(name, parentId);
      refresh();
    }
  };

  const handleAddTreasure = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.title || !newDoc.githubUrl) return;
    storageService.addDocument({
      ...newDoc,
      categoryId: showDocModal.catId
    });
    setNewDoc({ title: '', description: '', githubUrl: '' });
    setShowDocModal({ show: false, catId: '' });
    refresh();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-3 ${level > 0 ? 'ml-6 border-l border-white/10 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const hasSubCats = categories.some(c => c.parentId === cat.id);
          const hasDocs = documents.some(d => d.categoryId === cat.id);

          return (
            <div key={cat.id} className="group bg-white/5 p-3 rounded-xl border border-transparent hover:border-cyan-500/30 transition-all">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <span className={`text-lg ${level === 0 ? 'opacity-100' : 'opacity-50'}`}>
                    {level === 0 ? '🌳' : level === 1 ? '🍃' : '🐛'}
                  </span>
                  <span className={`font-bold ${level === 0 ? 'text-white text-lg' : 'text-white/70 text-sm'}`}>
                    {cat.name}
                  </span>
                  {hasDocs && <span className="bg-cyan-500/20 text-cyan-400 text-[8px] px-1.5 py-0.5 rounded font-black uppercase">Trésor</span>}
                </div>

                <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => handleAddBranch(cat.id)}
                    className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-cyan-400 transition-colors"
                    title="Ajouter une branche"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                  </button>

                  {/* On ne peut mettre un document que si c'est la fin de la branche ou déjà un dossier de doc */}
                  {!hasSubCats && (
                    <button 
                      onClick={() => setShowDocModal({ show: true, catId: cat.id })}
                      className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-yellow-400 transition-colors"
                      title="Ajouter un document (Trésor)"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>
                    </button>
                  )}

