                  </button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/90 rounded-[2.5rem] border border-white/10 overflow-hidden shadow-2xl backdrop-blur-3xl animate-in zoom-in-95 duration-500">
