                   <span className="text-white/20">[{log.timestamp}]</span>
                   <span className="text-cyan-400 font-black uppercase">{log.action}</span>
                   <span className="text-white/50">{log.details}</span>
                 </div>
               ))}
             </div>
          </div>
        )}
      </div>

      {showDocModal.show && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 backdrop-blur-3xl">
          <div className="absolute inset-0 bg-black/90" onClick={() => setShowDocModal({ show: false, catId: '' })}></div>
          <form 
            onSubmit={handlePublishDocument}
            className="bg-slate-900 border border-white/20 rounded-[2.5rem] p-12 max-w-md w-full relative z-10 shadow-2xl animate-in zoom-in-95 duration-200"
          >
            <h4 className="text-3xl font-black text-white mb-8 italic tracking-tighter uppercase">📁 Publication de <span className="text-cyan-400">Document</span></h4>

            <div className="space-y-6 mb-10">
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 uppercase font-black tracking-widest ml-2">Titre de la ressource</label>
                <input 
                  required
                  type="text" 
                  placeholder="Ex: Analyse Algébrique" 
                  value={newDoc.title}
                  onChange={(e) => setNewDoc({...newDoc, title: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:border-cyan-400 outline-none transition-all"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 uppercase font-black tracking-widest ml-2">Description technique</label>
                <input 
                  type="text" 
                  placeholder="Informations complémentaires..." 
                  value={newDoc.description}
                  onChange={(e) => setNewDoc({...newDoc, description: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:border-cyan-400 outline-none transition-all"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] text-white/30 uppercase font-black tracking-widest ml-2">Fichier source (Stockage Local)</label>
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`w-full border-2 border-dashed rounded-2xl p-8 flex flex-col items-center justify-center gap-3 cursor-pointer transition-all ${
                    selectedFile 
                      ? 'bg-cyan-500/10 border-cyan-400/50' 
                      : 'bg-white/5 border-white/10 hover:border-cyan-400/30'
                  }`}
                >
                  <input 
                    type="file"
                    accept=".pdf"
                    className="hidden"
                    ref={fileInputRef}
                    onChange={handleFileChange}
                  />
                  {selectedFile ? (
                    <>
                      <svg className="w-10 h-10 text-cyan-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4zm2 6a1 1 0 011-1h6a1 1 0 110 2H7a1 1 0 01-1-1zm1 3a1 1 0 100 2h6a1 1 0 100-2H7z" clipRule="evenodd" /></svg>
                      <span className="text-white font-bold text-center text-sm">{selectedFile.name}</span>
                      <span className="text-cyan-400/50 text-[10px] font-black uppercase">Changer de fichier</span>
                    </>
                  ) : (
                    <>
                      <svg className="w-10 h-10 text-white/10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                      <span className="text-white/20 text-sm font-medium text-center">Cliquez ici pour accéder à votre stockage</span>
                    </>
                  )}
                </div>
              </div>
            </div>

            <div className="flex gap-4">
              <button 
                type="button"
                onClick={() => { setShowDocModal({ show: false, catId: '' }); setSelectedFile(null); }}
                className="flex-1 bg-white/5 text-white/40 font-black py-4 rounded-2xl uppercase text-[10px] tracking-widest hover:bg-white/10 transition-all"
              >Annuler</button>
              <button 
                type="submit"
                disabled={!selectedFile}
                className="flex-1 bg-cyan-500 disabled:opacity-30 text-slate-950 font-black py-4 rounded-2xl uppercase text-[10px] tracking-widest hover:bg-cyan-400 transition-all shadow-lg shadow-cyan-500/20"
              >Publier</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground';
import DocumentCard from './components/DocumentCard';
import AdminDashboard from './components/AdminDashboard';
import { storageService } from './services/storageService';
import { Category, Document, UserSession } from './types';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Navigation State
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);

  // Auth & UI States
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);

  const [userSession, setUserSession] = useState<UserSession | null>(null);
  const [showEmailModal, setShowEmailModal] = useState(false);
  const [pendingDoc, setPendingDoc] = useState<Document | null>(null);
  const [emailInput, setEmailInput] = useState('');

  // Notification Alert
  const [showNewAlert, setShowNewAlert] = useState(false);

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    if (storageService.getNewPostFlag()) {
      setShowNewAlert(true);
    }
  };

  useEffect(() => {
    refreshData();
    setUserSession(storageService.getUser());
    storageService.updateStats(1, 0);

    const interval = setInterval(() => {
      const docs = storageService.getDocuments();
      const lastCount = Number(localStorage.getItem('sp_last_count') || docs.length);
      if (docs.length > lastCount) {
        setShowNewAlert(true);
      }
    }, 10000);
    return () => clearInterval(interval);
  }, [isAdminMode]);

  const navigateTo = (cat: Category | null) => {
    if (!cat) {
      setNavigationPath([]);
      storageService.trackMovement("Accueil");
    } else {
      const newPath = [...navigationPath, cat];
      setNavigationPath(newPath);
      storageService.trackMovement(newPath.map(c => c.name).join(" > "));
    }
  };

  const goBackTo = (index: number | null) => {
    if (index === null) {
      setNavigationPath([]);
      storageService.trackMovement("Retour Index");
    } else {
      const newPath = navigationPath.slice(0, index + 1);
      setNavigationPath(newPath);
      storageService.trackMovement("Navigation vers " + newPath.map(c => c.name).join(" > "));
    }
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath]);

  const currentLevelDocuments = useMemo(() => {
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath]);

  const handleDownload = async (doc: Document) => {
    if (userSession?.isValidated) {
      if (doc.isLocal) {
        const blob = await storageService.getFileBinary(doc.githubUrl);
        if (blob) {
          const url = URL.createObjectURL(blob);
          const a = window.document.createElement('a');
          a.href = url;
          a.download = `${doc.title}.pdf`;
          window.document.body.appendChild(a);
          a.click();
          window.document.body.removeChild(a);
          URL.revokeObjectURL(url);
        } else {
          alert("Le fichier local n'est plus accessible sur cet appareil.");
        }
      } else {
        window.open(doc.githubUrl, '_blank');
      }
      storageService.incrementDownload(doc.id);
      refreshData();
    } else {
      setPendingDoc(doc);
      setShowEmailModal(true);
    }
  };

  const handleEmailSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (emailInput.includes('@')) {
      storageService.setUser(emailInput);
      setUserSession({ email: emailInput, isValidated: true });
      setShowEmailModal(false);
      if (pendingDoc) handleDownload(pendingDoc);
    }
  };

  const dismissAlert = () => {
    setShowNewAlert(false);
    storageService.acknowledgeNewPosts();
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminUsername === 'Léon' && adminPassword === 'mazedxn7') {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      setLoginError(false);
      setAdminUsername('');
      setAdminPassword('');
      storageService.addLog('Authentification', 'Accès administrateur validé pour Léon.');
    } else {
      setLoginError(true);
      setTimeout(() => setLoginError(false), 2000);
    }
  };

  return (
    <div className="min-h-screen relative pb-40 text-slate-100 selection:bg-cyan-500/30">
      <AuroraBackground />

      {showNewAlert && !isAdminMode && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[200] bg-gradient-to-r from-cyan-600 to-violet-600 text-white px-10 py-5 rounded-full shadow-[0_20px_50px_rgba(0,0,0,0.4)] flex items-center gap-6 animate-in slide-in-from-top-20 duration-700 border border-white/20">
          <div className="bg-white/20 p-2 rounded-full animate-bounce">
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a6 6 0 00-6 6v3.586l-.707.707A1 1 0 004 14h12a1 1 0 00.707-1.707L16 11.586V8a6 6 0 00-6-6zM10 18a3 3 0 01-3-3h6a3 3 0 01-3 3z" /></svg>
          </div>
          <div className="flex flex-col">
             <span className="font-black uppercase text-[10px] tracking-[0.3em]">Mise à jour</span>
             <span className="font-bold text-sm">De nouveaux documents ont été publiés.</span>
          </div>
          <button onClick={dismissAlert} className="ml-4 bg-black/10 hover:bg-black/20 p-2 rounded-full transition-all active:scale-90">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
      )}

      <header className="container mx-auto px-8 py-16 flex flex-col lg:flex-row items-center justify-between gap-12">
        <div className="flex items-center gap-6 cursor-pointer group" onClick={() => navigateTo(null)}>
          <div className="w-16 h-16 bg-cyan-500 rounded-2xl flex items-center justify-center shadow-2xl group-hover:rotate-12 group-hover:scale-110 transition-all duration-500">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" /></svg>
          </div>
          <div>
            <h1 className="text-5xl font-black tracking-tighter text-white">SUCCESS<span className="text-cyan-400">POLARIS</span></h1>
            <p className="text-[10px] uppercase tracking-[0.5em] text-white/30 font-black mt-1">Système de Gestion Documentaire</p>
          </div>
        </div>

        {!isAdminMode && (
          <div className="relative w-full max-w-md group">
            <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none">
              <svg className="h-5 w-5 text-white/20 group-focus-within:text-cyan-400 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input 
              type="text" 
              placeholder="Rechercher un document..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-full pl-14 pr-8 py-4 text-sm focus:border-cyan-400/50 outline-none backdrop-blur-3xl transition-all focus:ring-4 ring-cyan-500/10"
            />
          </div>
        )}
      </header>

      <main className="container mx-auto px-8">
        {isAdminMode ? (
          <div className="animate-in fade-in zoom-in-95 duration-500">
            <div className="flex justify-between items-center mb-8">
               <h2 className="text-2xl font-black text-white italic tracking-tight">CONSOLE D'ADMINISTRATION</h2>
               <button 
                  onClick={() => setIsAdminMode(false)}
                  className="bg-white/10 hover:bg-white/20 text-white px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all"
               >Déconnexion</button>
            </div>
            <AdminDashboard />
          </div>
        ) : (
          <div className="space-y-16">
            <div className="bg-white/5 p-6 rounded-[2rem] border border-white/10 backdrop-blur-2xl">
              <div className="flex flex-wrap items-center gap-3">
                <button 
                  onClick={() => goBackTo(null)}
                  className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${navigationPath.length === 0 ? 'bg-cyan-500 text-slate-950' : 'text-white/40 hover:text-white hover:bg-white/5'}`}
                >📂 Index</button>
                {navigationPath.map((cat, i) => (
                  <React.Fragment key={cat.id}>
                    <span className="text-white/10">❯</span>
                    <button 
                      onClick={() => goBackTo(i)}
                      className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${i === navigationPath.length - 1 ? 'bg-cyan-500 text-slate-950' : 'text-white/40 hover:text-white hover:bg-white/5'}`}
                    >
                      {cat.name}
                    </button>
                  </React.Fragment>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
              <div className="lg:col-span-4 space-y-10">
                <div>
                   <h3 className="text-white/20 text-[10px] font-black uppercase tracking-[0.4em] mb-8 flex items-center gap-4">
                     <span className="w-12 h-[1px] bg-white/10"></span> NAVIGATION
                   </h3>
                   <div className="grid grid-cols-1 gap-3">
                     {currentLevelCategories.map(cat => (
                       <button 
                         key={cat.id}
                         onClick={() => navigateTo(cat)}
                         className="w-full flex items-center justify-between p-7 bg-white/5 border border-transparent hover:border-cyan-500/30 hover:bg-white/10 rounded-3xl transition-all group active:scale-[0.98]"
                       >
                         <div className="flex items-center gap-5">
                            <span className="text-2xl group-hover:scale-125 transition-transform duration-300">
                              {navigationPath.length === 0 ? '📁' : '📂'}
                            </span>
                            <span className="text-lg font-bold text-white/60 group-hover:text-white">{cat.name}</span>
                         </div>
                         <svg className="w-6 h-6 text-white/10 group-hover:text-cyan-400 transition-all group-hover:translate-x-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" /></svg>
                       </button>
                     ))}
                     {currentLevelCategories.length === 0 && navigationPath.length > 0 && (
                       <div className="p-10 border border-dashed border-white/10 rounded-3xl text-center">
                          <p className="text-white/20 italic text-sm">Fin de l'arborescence actuelle.</p>
                       </div>
                     )}
                     {currentLevelCategories.length === 0 && navigationPath.length === 0 && (
                       <p className="text-white/20 italic">Aucune catégorie n'est répertoriée.</p>
                     )}
                   </div>
                </div>
              </div>

              <div className="lg:col-span-8 space-y-10">
                 <h3 className="text-white/20 text-[10px] font-black uppercase tracking-[0.4em] mb-8 flex items-center gap-4">
                  <span className="w-12 h-[1px] bg-white/10"></span> FICHIERS DISPONIBLES
                </h3>

                {currentLevelDocuments.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-right-10 duration-700">
                    {currentLevelDocuments.map(doc => (
                      <DocumentCard key={doc.id} doc={doc} onDownload={handleDownload} />
                    ))}
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center py-40 bg-white/5 rounded-[3.5rem] border border-dashed border-white/10 group">
                    <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mb-8 group-hover:scale-110 transition-transform duration-500">
                      <svg className="w-12 h-12 text-white/10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                    </div>
                    <p className="text-white/30 text-lg font-medium text-center max-w-xs leading-relaxed">
                      {navigationPath.length === 0 
                        ? "Veuillez sélectionner une catégorie pour afficher les documents."
                        : "Cette catégorie ne contient aucun document pour le moment."}
                    </p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full p-10 bg-slate-950/80 backdrop-blur-3xl border-t border-white/5 flex flex-col md:flex-row items-center justify-between z-50">
        <div className="flex items-center gap-6">
          <p className="text-[10px] text-white/20 font-black uppercase tracking-[0.6em]">Polaris Core v3.1</p>
          <div className="h-1.5 w-1.5 rounded-full bg-cyan-500 shadow-[0_0_10px_#00d4ff] animate-pulse"></div>
        </div>

        <button 
          onClick={() => setShowAdminLogin(true)}
          className="group relative px-8 py-3 overflow-hidden rounded-xl"
        >
          <span className="relative z-10 text-[10px] text-cyan-400/50 group-hover:text-cyan-400 uppercase tracking-[0.4em] font-black transition-all">
            Développé par <span className="underline decoration-cyan-400/20 underline-offset-8">Astarté</span> (Némésis)
          </span>
          <div className="absolute inset-0 bg-cyan-500/5 translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
        </button>
      </footer>

      {showEmailModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 backdrop-blur-3xl">
          <div className="absolute inset-0 bg-black/95" onClick={() => setShowEmailModal(false)}></div>
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] p-12 max-w-md w-full relative z-10 shadow-2xl animate-in zoom-in-95 duration-300">
             <div className="w-20 h-20 bg-cyan-500/10 rounded-2xl flex items-center justify-center mb-10 mx-auto border border-cyan-500/20">
                <svg className="w-10 h-10 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 00-2 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
             </div>
             <h3 className="text-3xl font-black text-white text-center mb-4 italic tracking-tighter">ACCÈS DOCUMENTAIRE</h3>
             <p className="text-white/40 text-sm text-center mb-10 leading-relaxed">Veuillez renseigner votre email pour débloquer <span className="text-cyan-400 font-black">"{pendingDoc?.title}"</span>.</p>

             <form onSubmit={handleEmailSubmit} className="space-y-6">
                <input 
                  type="email" 
                  required
                  placeholder="votre@email.com" 
                  value={emailInput}
                  onChange={(e) => setEmailInput(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 text-white outline-none focus:border-cyan-400 transition-all text-center"
                />
                <button 
                  type="submit"
                  className="w-full bg-cyan-500 text-slate-950 font-black py-5 rounded-3xl uppercase tracking-widest shadow-2xl shadow-cyan-500/20 hover:bg-cyan-400 transition-all transform active:scale-95"
                >Débloquer le téléchargement</button>
             </form>
          </div>
        </div>
      )}

      {showAdminLogin && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 backdrop-blur-[50px]">
          <div className="absolute inset-0 bg-black/95" onClick={() => setShowAdminLogin(false)}></div>
          <div className="bg-slate-900 border border-white/10 rounded-[3.5rem] p-14 max-w-md w-full relative z-10 shadow-[0_0_100px_rgba(0,0,0,0.8)] animate-in slide-in-from-bottom-20 duration-500">
            <div className="text-center mb-12">
               <div className="inline-block px-5 py-1.5 bg-cyan-500/10 border border-cyan-500/20 rounded-full text-cyan-400 text-[9px] font-black uppercase tracking-[0.5em] mb-6">Nexus Administratif</div>
               <h3 className="text-4xl font-black text-white italic tracking-tighter">AUTHENTIFICATION</h3>
            </div>

            <form onSubmit={handleAdminLoginSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 uppercase font-black tracking-widest ml-4">Utilisateur</label>
                <input 
                  type="text" 
                  required
                  placeholder="Identifiant" 
                  value={adminUsername}
                  onChange={(e) => setAdminUsername(e.target.value)}
                  className={`w-full bg-black/40 border ${loginError ? 'border-red-500' : 'border-white/5'} rounded-2xl px-8 py-5 text-white outline-none focus:border-cyan-400/50 transition-all`}
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 uppercase font-black tracking-widest ml-4">Mot de Passe</label>
                <input 
                  type="password" 
                  required
                  placeholder="Code de sécurité" 
                  value={adminPassword}
                  onChange={(e) => setAdminPassword(e.target.value)}
                  className={`w-full bg-black/40 border ${loginError ? 'border-red-500' : 'border-white/5'} rounded-2xl px-8 py-5 text-white outline-none focus:border-cyan-400/50 transition-all`}
                />
              </div>

              {loginError && (
                <p className="text-red-500 text-[10px] font-black uppercase text-center animate-bounce">Identifiants incorrects. Accès refusé.</p>
              )}

              <button 
                type="submit"
                className="w-full bg-white text-slate-950 font-black py-6 mt-6 rounded-[2rem] uppercase tracking-[0.2em] shadow-2xl hover:bg-cyan-400 transition-all active:scale-95 transform"
              >Accéder à la console</button>
            </form>

            <p className="text-center text-white/20 text-[8px] uppercase font-black tracking-[0.3em] mt-10">Polaris Secure Access Protocol</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface Category {
  id: string;
  name: string;
  parentId: string | null;
}

export interface Document {
  id: string;
  title: string;
  description: string;
  categoryId: string;
  githubUrl: string; // Utilisé comme URL externe ou ID de référence locale
  downloads: number;
  dateAdded: string;
  isLocal?: boolean; // Flag pour le stockage IndexedDB
}

export interface VisitorActivity {
  id: string;
  path: string;
  timestamp: string;
}

export interface Stats {
  totalVisits: number;
  totalDownloads: number;
}

export interface UserSession {
  email: string;
  country?: string;
  isValidated: boolean;
}

export interface ActivityLog {
  id: string;
  action: string;
  timestamp: string;
  details: string;
}

import { Category, Document, Stats, ActivityLog, VisitorActivity, UserSession } from '../types';
import { INITIAL_CATEGORIES, INITIAL_DOCUMENTS } from '../constants';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  USER: 'sp_user_session',
  LAST_DOC_COUNT: 'sp_last_count',
  ACTIVITY: 'sp_visitor_activity'
};

// Initialisation de IndexedDB pour les fichiers volumineux
const dbPromise = new Promise<IDBDatabase>((resolve, reject) => {
  const request = indexedDB.open('SuccessPolarisDB', 1);
  request.onupgradeneeded = () => {
    if (!request.result.objectStoreNames.contains('files')) {
      request.result.createObjectStore('files');
    }
  };
  request.onsuccess = () => resolve(request.result);
  request.onerror = () => reject(request.error);
});

export const storageService = {
  // Gestion des fichiers binaires (IndexedDB)
  saveFileBinary: async (id: string, file: File): Promise<void> => {
    const db = await dbPromise;
    return new Promise((resolve, reject) => {
      const tx = db.transaction('files', 'readwrite');
      tx.objectStore('files').put(file, id);
      tx.oncomplete = () => resolve();
      tx.onerror = () => reject(tx.error);
    });
  },

  getFileBinary: async (id: string): Promise<Blob | null> => {
    const db = await dbPromise;
    return new Promise((resolve, reject) => {
      const tx = db.transaction('files', 'readonly');
      const request = tx.objectStore('files').get(id);
      request.onsuccess = () => resolve(request.result || null);
      request.onerror = () => reject(request.error);
    });
  },

  deleteFileBinary: async (id: string): Promise<void> => {
    const db = await dbPromise;
    return new Promise((resolve, reject) => {
      const tx = db.transaction('files', 'readwrite');
      tx.objectStore('files').delete(id);
      tx.oncomplete = () => resolve();
      tx.onerror = () => reject(tx.error);
    });
  },

  // Categories
  getCategories: (): Category[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    return data ? JSON.parse(data) : INITIAL_CATEGORIES;
  },
  saveCategory: (name: string, parentId: string | null) => {
    const cats = storageService.getCategories();
    const newCat = { id: `cat-${Date.now()}`, name, parentId };
    storageService.saveCategories([...cats, newCat]);
    storageService.addLog('Architecture', `Nouvelle catégorie créée : ${name}`);
    return newCat;
  },
  saveCategories: (cats: Category[]) => {
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(cats));
  },
  deleteCategory: (id: string) => {
    const cats = storageService.getCategories().filter(c => c.id !== id);
    const docs = storageService.getDocuments().filter(d => d.categoryId === id);

    docs.forEach(doc => {
      if (doc.isLocal) storageService.deleteFileBinary(doc.githubUrl);
    });

    const remainingDocs = storageService.getDocuments().filter(d => d.categoryId !== id);
    storageService.saveCategories(cats);
    storageService.saveDocuments(remainingDocs);
    storageService.addLog('Architecture', `Suppression de l'entrée d'index ${id}`);
  },

  // Documents
  getDocuments: (): Document[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    return data ? JSON.parse(data) : INITIAL_DOCUMENTS;
  },
  saveDocuments: (docs: Document[]) => {
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
  },
  addDocument: async (docData: Omit<Document, 'id' | 'downloads' | 'dateAdded'>, file?: File) => {
    const docs = storageService.getDocuments();
    const id = `doc-${Date.now()}`;
    let githubUrl = docData.githubUrl;
    let isLocal = false;

    if (file) {
      const fileId = `file-${Date.now()}`;
      await storageService.saveFileBinary(fileId, file);
      githubUrl = fileId;
      isLocal = true;
    }

    const newDoc: Document = {
      ...docData,
      id,
      githubUrl,
      isLocal,
      downloads: 0,
      dateAdded: new Date().toISOString()
    };
    storageService.saveDocuments([newDoc, ...docs]);
    storageService.addLog('Publication', `Indexation du document : ${docData.title}`);
  },

  incrementDownload: (id: string) => {
    const docs = storageService.getDocuments();
    const docIndex = docs.findIndex(d => d.id === id);
    if (docIndex > -1) {
      docs[docIndex].downloads += 1;
      storageService.saveDocuments(docs);
      storageService.updateStats(0, 1);
      storageService.addLog('Transfert', `Téléchargement validé pour : ${docs[docIndex].title}`);
    }
  },

  // Visitor Tracking
  trackMovement: (path: string) => {
    const activities = storageService.getVisitorActivities();
    const newAct = {
      id: Math.random().toString(36).substr(2, 9),
      path,
      timestamp: new Date().toISOString()
    };
    localStorage.setItem(KEYS.ACTIVITY, JSON.stringify([newAct, ...activities].slice(0, 20)));
  },
  getVisitorActivities: (): VisitorActivity[] => {
    const data = localStorage.getItem(KEYS.ACTIVITY);
    return data ? JSON.parse(data) : [];
  },

  // Stats & Logs
  getStats: (): Stats => {
    const data = localStorage.getItem(KEYS.STATS);
    return data ? JSON.parse(data) : { totalVisits: 0, totalDownloads: 0 };
  },
  updateStats: (v: number, d: number) => {
    const s = storageService.getStats();
    localStorage.setItem(KEYS.STATS, JSON.stringify({ totalVisits: s.totalVisits + v, totalDownloads: s.totalDownloads + d }));
  },
  getLogs: (): ActivityLog[] => {
    const data = localStorage.getItem(KEYS.LOGS);
    return data ? JSON.parse(data) : [];
  },
  addLog: (action: string, details: string) => {
    const logs = storageService.getLogs();
    const newLog = { id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.LOGS, JSON.stringify([newLog, ...logs].slice(0, 50)));
  },

  // User Session Management
  getUser: (): UserSession | null => {
    const data = localStorage.getItem(KEYS.USER);
    return data ? JSON.parse(data) : null;
  },
  setUser: (email: string, country: string) => {
    const session: UserSession = { email, country, isValidated: true };
    localStorage.setItem(KEYS.USER, JSON.stringify(session));
    storageService.addLog('Utilisateur', `Nouveau profil validé : ${email} (${country})`);
  },
  getNewPostFlag: () => {
    const count = storageService.getDocuments().length;
    const lastCount = Number(localStorage.getItem(KEYS.LAST_DOC_COUNT) || count);
    return count > lastCount;
  },
  acknowledgeNewPosts: () => {
    localStorage.setItem(KEYS.LAST_DOC_COUNT, storageService.getDocuments().length.toString());
  }
};

import React, { useState, useEffect, useMemo } from 'react';
