          <div className="bg-slate-900 border border-white/10 rounded-[3rem] p-12 max-w-md w-full relative z-10 shadow-2xl animate-in zoom-in-95 duration-300">

             {/* Étape 1 : Email */}
             {verifyStep === 'email' && (
               <div className="animate-in fade-in duration-300">
                 <div className="w-20 h-20 bg-cyan-500/10 rounded-2xl flex items-center justify-center mb-8 mx-auto border border-cyan-500/20">
                    <svg className="w-10 h-10 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 00-2 2z" /></svg>
                 </div>
                 <h3 className="text-3xl font-black text-white text-center mb-4 italic tracking-tighter uppercase">VÉRIFICATION</h3>
                 <p className="text-white/40 text-sm text-center mb-10 leading-relaxed">Un code de sécurité sera envoyé par <span className="text-cyan-400 font-bold">leonemmanuel6247@gmail.com</span>.</p>

                 <form onSubmit={initiateEmailVerification} className="space-y-6">
