                      placeholder="votre@email.com" 
                      value={emailInput}
                      onChange={(e) => setEmailInput(e.target.value)}
                      className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 text-white outline-none focus:border-cyan-400 transition-all text-center font-bold"
                    />
                    {verifyError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{verifyError}</p>}
                    <button 
                      type="submit"
                      disabled={isSending}
                      className="w-full bg-cyan-500 text-slate-950 font-black py-5 rounded-3xl uppercase tracking-widest hover:bg-cyan-400 transition-all transform active:scale-95 disabled:opacity-50"
                    >
                      {isSending ? 'ENVOI EN COURS...' : 'ENVOYER LE CODE'}
                    </button>
                 </form>
               </div>
             )}

             {/* Étape 2 : OTP (4 chiffres) */}
             {verifyStep === 'otp' && (
               <div className="animate-in slide-in-from-right-10 duration-300">
                 <div className="w-20 h-20 bg-yellow-500/10 rounded-2xl flex items-center justify-center mb-8 mx-auto border border-yellow-500/20">
                    <svg className="w-10 h-10 text-yellow-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 00-2 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                 </div>
                 <h3 className="text-3xl font-black text-white text-center mb-4 italic tracking-tighter uppercase">CODE REÇU ?</h3>
                 <p className="text-white/40 text-sm text-center mb-10 leading-relaxed">Entrez les 4 chiffres envoyés à <br/><span className="text-white font-bold">{emailInput}</span>.</p>

                 <form onSubmit={handleOtpSubmit} className="space-y-6">
                    <input 
                      type="text" 
                      maxLength={4}
                      required
                      placeholder="0 0 0 0" 
                      value={otpInput}
                      onChange={(e) => setOtpInput(e.target.value.replace(/\D/g, ''))}
                      className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 text-white outline-none focus:border-yellow-400 transition-all text-center text-4xl font-black tracking-[0.5em]"
                    />
                    {verifyError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{verifyError}</p>}
                    <div className="flex flex-col gap-3">
                      <button 
                        type="submit"
                        className="w-full bg-white text-slate-950 font-black py-5 rounded-3xl uppercase tracking-widest hover:bg-yellow-400 transition-all transform active:scale-95"
                      >VÉRIFIER LE CODE</button>
                      <button 
                        type="button"
                        onClick={() => setVerifyStep('email')}
                        className="text-[10px] text-white/30 uppercase font-black tracking-widest hover:text-white transition-colors"
                      >Modifier l'email</button>
                    </div>
                 </form>
               </div>
             )}

             {/* Étape 3 : Pays */}
             {verifyStep === 'country' && (
               <div className="animate-in slide-in-from-right-10 duration-300">
                 <div className="w-20 h-20 bg-green-500/10 rounded-2xl flex items-center justify-center mb-8 mx-auto border border-green-500/20">
                    <svg className="w-10 h-10 text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                 </div>
                 <h3 className="text-3xl font-black text-white text-center mb-4 italic tracking-tighter uppercase">DERNIÈRE ÉTAPE</h3>
                 <p className="text-white/40 text-sm text-center mb-10 leading-relaxed">Pour finaliser votre profil SuccessPolaris : <br/><span className="text-white font-bold">De quel pays venez-vous ?</span></p>

                 <form onSubmit={handleCountrySubmit} className="space-y-6">
                    <input 
                      type="text" 
                      required
                      autoFocus
                      placeholder="Votre pays d'origine" 
                      value={countryInput}
                      onChange={(e) => setCountryInput(e.target.value)}
                      className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 text-white outline-none focus:border-green-400 transition-all text-center font-bold"
                    />
                    {verifyError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{verifyError}</p>}
                    <button 
                      type="submit"
                      className="w-full bg-green-500 text-slate-950 font-black py-5 rounded-3xl uppercase tracking-widest hover:bg-green-400 transition-all transform active:scale-95 shadow-xl shadow-green-500/20"
                    >ACCÉDER AU DOCUMENT</button>
                 </form>
               </div>
             )}

          </div>
        </div>
      )}

      {/* LOGIN ADMIN MODAL */}
      {showAdminLogin && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 backdrop-blur-[50px]">
          <div className="absolute inset-0 bg-black/95" onClick={() => setShowAdminLogin(false)}></div>
          <div className="bg-slate-900 border border-white/10 rounded-[3.5rem] p-14 max-w-md w-full relative z-10 shadow-[0_0_100px_rgba(0,0,0,0.8)] animate-in slide-in-from-bottom-20 duration-500">
            <div className="text-center mb-12">
               <div className="inline-block px-5 py-1.5 bg-cyan-500/10 border border-cyan-500/20 rounded-full text-cyan-400 text-[9px] font-black uppercase tracking-[0.5em] mb-6">Nexus Administratif</div>
               <h3 className="text-4xl font-black text-white italic tracking-tighter">AUTHENTIFICATION</h3>
            </div>

            <form onSubmit={handleAdminLoginSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 uppercase font-black tracking-widest ml-4">Utilisateur</label>
                <input 
                  type="text" 
                  required
                  placeholder="Identifiant" 
                  value={adminUsername}
                  onChange={(e) => setAdminUsername(e.target.value)}
                  className={`w-full bg-black/40 border ${loginError ? 'border-red-500' : 'border-white/5'} rounded-2xl px-8 py-5 text-white outline-none focus:border-cyan-400/50 transition-all`}
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 uppercase font-black tracking-widest ml-4">Mot de Passe</label>
                <input 
                  type="password" 
                  required
                  placeholder="Code de sécurité" 
                  value={adminPassword}
                  onChange={(e) => setAdminPassword(e.target.value)}
                  className={`w-full bg-black/40 border ${loginError ? 'border-red-500' : 'border-white/5'} rounded-2xl px-8 py-5 text-white outline-none focus:border-cyan-400/50 transition-all`}
                />
