                </div>
              </div>
            </div>

            <div className="flex gap-4">
              <button 
                type="button"
                onClick={() => { setShowDocModal({ show: false, catId: '' }); }}
                className="flex-1 bg-white/5 text-white/40 font-black py-4 rounded-2xl uppercase text-[10px] tracking-widest hover:bg-white/10 transition-all"
              >Annuler</button>
              <button 
                type="submit"
                className="flex-1 bg-cyan-500 text-slate-950 font-black py-4 rounded-2xl uppercase text-[10px] tracking-widest hover:bg-cyan-400 transition-all shadow-lg shadow-cyan-500/20"
              >Indexer</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

