export const GOOGLE_SHEET_ID = '1XpY_vOTRE_ID_ICI'; 

export const INITIAL_CATEGORIES: Category[] = [
  { id: 'cat-maths', name: 'Mathématiques', parentId: null, icon: '📐' },
  { id: 'cat-physique', name: 'Physique-Chimie', parentId: null, icon: '🧪' }
