              placeholder="Explorer les archives de SuccessPolaris..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-slate-950/70 border border-white/10 rounded-[2rem] md:rounded-[2.5rem] pl-16 md:pl-20 pr-8 md:pr-10 py-5 md:py-7 text-[13px] md:text-[15px] focus:border-cyan-400/60 outline-none backdrop-blur-3xl transition-all placeholder:text-white/10 text-white font-black relative z-10 shadow-2xl"
            />
          </div>
        )}
      </header>

      <main className="container mx-auto px-6 md:px-12 lg:px-24 relative z-10">
        {isAdminMode ? (
          <div className="space-y-12 animate-in">
            <div className="flex justify-between items-center mb-12 border-b border-white/5 pb-8">
              <div className="flex items-center gap-6">
                 <div className="w-4 h-4 bg-cyan-400 rounded-full shadow-[0_0_25px_#00d4ff] animate-pulse"></div>
                 <h2 className="text-lg md:text-xl font-black uppercase italic tracking-[0.4em] text-white">Console de Contrôle Polaris</h2>
              </div>
              <button 
                onClick={() => setIsAdminMode(false)}
                className="bg-white/5 hover:bg-red-500/20 hover:text-red-400 text-white/40 px-8 py-3 rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest border border-white/10 transition-all shadow-xl"
              >Quitter la Matrice</button>
            </div>
            <AdminDashboard 
              categories={categories} 
              documents={documents} 
              onRefresh={syncData} 
            />
          </div>
        ) : (
          <div className="space-y-16 md:space-y-24">
            <nav className="flex items-center gap-3 md:gap-5 overflow-x-auto no-scrollbar py-4 md:py-6 px-6 md:px-10 bg-slate-950/60 rounded-[2.5rem] md:rounded-[3rem] border border-white/5 backdrop-blur-3xl shadow-2xl">
              <button 
                onClick={() => navigateTo(null)}
                className={`px-8 md:px-12 py-3 md:py-4 rounded-[1.2rem] md:rounded-[1.5rem] text-[10px] md:text-[12px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${navigationPath.length === 0 ? 'bg-cyan-400 text-slate-950 shadow-[0_0_30px_rgba(0,212,255,0.4)]' : 'text-white/20 hover:text-white'}`}
              >Racine Polaris</button>
              {navigationPath.map((cat, i) => (
                <React.Fragment key={cat.id}>
                  <div className="w-1.5 h-1.5 bg-cyan-400/20 rounded-full shrink-0"></div>
                  <button 
                    onClick={() => goBackTo(i)}
                    className={`px-8 md:px-12 py-3 md:py-4 rounded-[1.2rem] md:rounded-[1.5rem] text-[10px] md:text-[12px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${i === navigationPath.length - 1 ? 'bg-white text-slate-950' : 'text-white/20 hover:text-white'}`}
                  >{cat.name}</button>
                </React.Fragment>
              ))}
            </nav>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 md:gap-20">
              {!searchQuery && (
                <div className="lg:col-span-4 space-y-6 md:space-y-10">
                  <h3 className="text-white/20 text-[9px] md:text-[11px] font-black uppercase tracking-[1em] mb-10 flex items-center gap-4 pl-3">
                    <div className="w-2 h-2 bg-cyan-500 rounded-full animate-ping"></div> Secteurs
                  </h3>
                  <div className="grid grid-cols-1 gap-4 md:gap-6">
                    {currentLevelCategories.map(cat => (
                      <button 
                        key={cat.id}
                        onClick={() => navigateTo(cat)}
                        className="w-full flex items-center justify-between p-8 md:p-10 bg-slate-900/40 border border-white/5 hover:border-cyan-500/40 rounded-[2.5rem] group transition-all duration-700 hover:bg-cyan-500/5 hover:-translate-y-2 backdrop-blur-md"
                      >
                        <div className="flex items-center gap-6 md:gap-8">
                          <span className="text-3xl opacity-50 group-hover:opacity-100 group-hover:scale-125 transition-all duration-700">{cat.icon || '🪐'}</span>
                          <span className="text-[15px] font-black text-white/90 group-hover:text-cyan-400 transition-colors uppercase tracking-tighter block leading-none">{cat.name}</span>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div className={`${searchQuery ? 'lg:col-span-12' : 'lg:col-span-8'} space-y-12`}>
                <h3 className="text-white/20 text-[9px] md:text-[11px] font-black uppercase tracking-[1em] mb-10 flex items-center gap-4 pl-3">
                   <div className="w-2 h-2 bg-indigo-500 rounded-full"></div> Archives
                </h3>
                {currentLevelDocuments.length > 0 ? (
                  <div className={`grid grid-cols-1 ${searchQuery ? 'sm:grid-cols-2 lg:grid-cols-3' : 'sm:grid-cols-2'} gap-8 md:gap-12`}>
                    {currentLevelDocuments.map(doc => (
                      <DocumentCard key={doc.id} doc={doc} onDownload={initiateDownload} />
                    ))}
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center py-32 md:py-48 bg-slate-900/10 rounded-[4rem] md:rounded-[5rem] border border-dashed border-white/5">
                    <p className="text-white/10 text-[13px] font-black uppercase tracking-[1.5em] animate-pulse-slow">Horizon vide</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer avec Porte Dérobée Astarté */}
      <footer className="fixed bottom-0 left-0 w-full py-4 px-6 md:px-12 bg-slate-950/90 backdrop-blur-3xl border-t border-white/5 flex flex-col sm:flex-row items-center justify-between z-[1000] gap-4">
        <div className="flex items-center gap-4">
          <div className="w-2 h-2 bg-cyan-500 rounded-full animate-pulse"></div>
          <p className="text-[8px] md:text-[9px] text-white/30 font-black uppercase tracking-[0.4em]">SuccessPolaris — Palace v1.0.1</p>
        </div>
        <div className="flex items-center gap-4 select-none">
          <p className="text-[8px] text-white/20 font-black uppercase tracking-widest">
            CRÉÉ PAR <span onClick={() => setShowAdminLogin(true)} className="hover:text-cyan-400 cursor-pointer transition-colors duration-500">ASTARTÉ</span> — MEMBRE DE NEMESIS
          </p>
        </div>
      </footer>

      {/* Modals */}
      {showEmailModal && (
        <div className="fixed inset-0 z-[6000] flex items-center justify-center p-6 bg-slate-950/98 backdrop-blur-3xl animate-in">
          <div className="max-w-[420px] w-full p-12 md:p-16 bg-slate-900/60 border border-white/15 rounded-[4rem] relative shadow-3xl">
            <button onClick={() => setShowEmailModal(false)} className="absolute top-10 right-10 text-white/20 hover:text-white text-2xl">×</button>
            <div className="text-center mb-10">
              <h3 className="text-md font-black text-white uppercase italic tracking-[0.5em] mb-3">Identification Requise</h3>
              <p className="text-[9px] text-white/30 font-bold uppercase">Format d'email vérifié par Polaris</p>
            </div>
            <form onSubmit={handleIdentityConfirm} className="space-y-10">
              <div className="bg-cyan-500/5 p-6 rounded-[2.5rem] border border-cyan-500/20 text-center font-black text-cyan-400">
                 {pendingDoc?.title}
              </div>
              <div className="space-y-2">
                <input type="email" required placeholder="votre@email.com" value={userEmail} onChange={e => { setUserEmail(e.target.value); setEmailError(''); }} className={`w-full bg-black/70 border ${emailError ? 'border-red-500' : 'border-white/10'} rounded-[1.5rem] px-8 py-5 text-white outline-none focus:border-cyan-400 font-black text-center transition-all`} />
                {emailError && <p className="text-center text-red-500 text-[9px] font-black uppercase">{emailError}</p>}
              </div>
              <button type="submit" className="w-full bg-cyan-400 hover:bg-white text-slate-950 font-black py-6 rounded-[1.5rem] uppercase text-[11px] tracking-[0.5em] transition-all">Accéder aux Archives</button>
            </form>
          </div>
        </div>
      )}

      {showAdminLogin && (
        <div className="fixed inset-0 z-[5000] flex items-center justify-center p-6 bg-black/98 backdrop-blur-3xl animate-in">
          <div className="max-w-[380px] w-full p-12 md:p-16 bg-slate-900/50 border border-white/15 rounded-[4rem] relative">
            <button onClick={() => setShowAdminLogin(false)} className="absolute top-10 right-10 text-white/20 hover:text-white text-2xl">×</button>
            <form onSubmit={handleAdminLogin} className="space-y-8">
              <div className="text-center">
                <div className="w-16 h-16 bg-cyan-500/10 rounded-3xl flex items-center justify-center mx-auto mb-6 border border-cyan-500/20">
                  <i className="fas fa-fingerprint text-cyan-400 text-2xl"></i>
                </div>
                <h3 className="text-white font-black uppercase tracking-[0.4em] mb-10 italic">Console Astarté</h3>
              </div>
              <input type="text" placeholder="Utilisateur" value={adminUsername} onChange={e => setAdminUsername(e.target.value)} className="w-full bg-black/80 border border-white/10 rounded-[1.5rem] px-8 py-6 text-white outline-none focus:border-cyan-400 text-center font-black" />
              <input type="password" placeholder="Clé Stellaire" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} className="w-full bg-black/80 border border-white/10 rounded-[1.5rem] px-8 py-6 text-white outline-none focus:border-cyan-400 text-center font-black" />
              {loginError && <p className="text-center text-red-500 text-[9px] font-black uppercase animate-pulse">Clé Invalide</p>}
              <button type="submit" className="w-full bg-white text-slate-950 font-black py-6 rounded-[1.5rem] uppercase tracking-widest hover:bg-cyan-400 transition-all">Éveil du Système</button>
            </form>
          </div>
        </div>
      )}

      {isSyncing && (
        <div className="fixed inset-0 z-[10000] flex flex-col items-center justify-center bg-slate-950/98 backdrop-blur-3xl">
           <div className="w-20 h-20 border-4 border-cyan-500/10 border-t-cyan-500 rounded-full animate-spin"></div>
           <p className="text-cyan-400 text-[10px] font-black uppercase tracking-[1em] mt-10 animate-pulse">Synchronisation Cloud...</p>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, VisitorActivity, AdminAccount } from '../types.ts';
import { GOOGLE_SHEET_ID } from '../constants.ts';

interface AdminDashboardProps {
  categories: Category[];
  documents: Document[];
  onRefresh?: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ categories, documents, onRefresh }) => {
  const [activeTab, setActiveTab] = useState<'status' | 'architect' | 'spy' | 'logs'>('status');
  const [activities, setActivities] = useState<VisitorActivity[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);

  // Form states
  const [parentSelection, setParentSelection] = useState<string>('root');
  const [mode, setMode] = useState<'category' | 'document'>('category');
  const [newItem, setNewItem] = useState({
    name: '',
    icon: '📁',
    title: '',
    description: '',
    url: '',
    size: '1.0 MB',
    tags: 'Cours|Révision'
  });

  const [generatedRow, setGeneratedRow] = useState<string>('');

  useEffect(() => {
    setActivities(storageService.getVisitorActivities());
  }, []);

  const handleManualSync = async () => {
    setIsSyncing(true);
    if (onRefresh) await onRefresh();
    setIsSyncing(false);
  };

  const generateDataRow = () => {
    const id = Math.random().toString(36).substr(2, 9);
    const parentId = parentSelection === 'root' ? '' : parentSelection;

    if (mode === 'category') {
      // id, name, parentId, icon
      setGeneratedRow(`${id},"${newItem.name}","${parentId}","${newItem.icon}"`);
    } else {
      // id, title, description, categoryId, fileUrl, fileType, tags, downloads, dateAdded, size
      const date = new Date().toISOString();
      const cleanUrl = newItem.url.trim();
      setGeneratedRow(`${id},"${newItem.title}","${newItem.description}","${parentId}","${cleanUrl}","pdf","${newItem.tags}",0,"${date}","${newItem.size}"`);
    }
  };

  return (
    <div className="bg-slate-950/40 rounded-[2rem] md:rounded-[3rem] border border-white/5 overflow-hidden backdrop-blur-3xl shadow-2xl flex flex-col min-h-[600px]">
      <div className="flex bg-black/60 overflow-x-auto no-scrollbar border-b border-white/10">
        {[
          { id: 'status', label: 'État Cloud', icon: '☁️' },
          { id: 'architect', label: 'Architecte', icon: '🏛️' },
          { id: 'spy', label: 'Espionnage', icon: '👁️' },
          { id: 'logs', label: 'Système', icon: '📟' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex-1 py-6 px-8 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap flex items-center justify-center gap-3 ${
              activeTab === tab.id ? 'border-cyan-500 bg-cyan-500/5 text-white' : 'border-transparent text-white/30 hover:text-white'
            }`}
          >
            <span className="text-sm">{tab.icon}</span>
            {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-12 flex-1 flex flex-col overflow-y-auto max-h-[700px] no-scrollbar">
        {activeTab === 'status' && (
          <div className="space-y-8 animate-in">
            <div className="bg-gradient-to-br from-slate-900 to-black p-10 rounded-[2.5rem] border border-white/10 shadow-inner">
               <h3 className="text-xl font-black text-white uppercase italic mb-6">Noyau de Données</h3>
               <p className="text-white/40 text-[11px] uppercase font-bold leading-relaxed tracking-widest mb-8">
                  Connecté à la nappe Google Sheets. Chaque ligne ajoutée dans le tableau devient une étoile dans votre galaxie.
               </p>
               <div className="flex flex-col sm:flex-row gap-4">
                  <button onClick={() => window.open(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/edit`, '_blank')}
                    className="flex-1 bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-lg"
                  >Ouvrir la Matrice Sheets</button>
                  <button onClick={handleManualSync} disabled={isSyncing}
                    className="flex-1 bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-500 hover:text-slate-950 transition-all"
                  >{isSyncing ? 'Synchronisation...' : 'Forcer la Mise à Jour'}</button>
               </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                {[
                  { label: 'Catégories', val: categories.length, color: 'text-cyan-400' },
                  { label: 'Documents', val: documents.length, color: 'text-indigo-400' },
                  { label: 'Dernière Sync', val: storageService.getLastSync().split('T')[1]?.slice(0,5) || 'OK', color: 'text-emerald-400' }
                ].map((stat, i) => (
                  <div key={i} className="bg-white/5 p-6 rounded-3xl border border-white/5 text-center">
                    <p className="text-[8px] text-white/20 uppercase font-black mb-1">{stat.label}</p>
                    <p className={`text-2xl font-black ${stat.color}`}>{stat.val}</p>
                  </div>
                ))}
            </div>
          </div>
        )}

        {activeTab === 'architect' && (
          <div className="space-y-10 animate-in">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              {/* Formulaire de création */}
              <div className="space-y-6">
                <div className="flex p-1 bg-black/40 rounded-2xl border border-white/10">
                  <button onClick={() => setMode('category')} className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${mode === 'category' ? 'bg-cyan-500 text-slate-950' : 'text-white/40'}`}>+ Catégorie</button>
                  <button onClick={() => setMode('document')} className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${mode === 'document' ? 'bg-indigo-500 text-slate-950' : 'text-white/40'}`}>+ Document</button>
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] text-white/40 font-black uppercase pl-2">Destination (Sous-Sous Catégorie)</label>
                  <select 
                    value={parentSelection}
                    onChange={(e) => setParentSelection(e.target.value)}
                    className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white text-[12px] outline-none focus:border-cyan-500 transition-all"
                  >
                    <option value="root">Racine (Catégorie Principale)</option>
                    {categories.map(c => (
                      <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                  </select>

                  {mode === 'category' ? (
                    <>
                      <input type="text" placeholder="Nom de la sous-catégorie" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white text-[12px] outline-none focus:border-cyan-500" />
                      <input type="text" placeholder="Icône (Emoji)" value={newItem.icon} onChange={e => setNewItem({...newItem, icon: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white text-[12px] outline-none focus:border-cyan-500" />
                    </>
                  ) : (
                    <>
                      <div className="bg-indigo-500/5 p-4 rounded-2xl border border-indigo-500/20 flex flex-col gap-3">
                        <p className="text-[8px] text-indigo-400 font-black uppercase tracking-widest text-center">Étape 1 : Récupérer le lien</p>
                        <button 
                          onClick={() => window.open('https://drive.google.com', '_blank')}
                          className="w-full bg-indigo-500/20 text-indigo-400 py-3 rounded-xl text-[9px] font-black uppercase border border-indigo-500/30 hover:bg-indigo-500 hover:text-white transition-all flex items-center justify-center gap-2"
                        >
                          <i className="fab fa-google-drive"></i> Ouvrir Google Drive
                        </button>
                      </div>

                      <div className="space-y-4 pt-2">
                        <p className="text-[8px] text-white/20 font-black uppercase tracking-widest pl-2 text-center">Étape 2 : Détails du document</p>
                        <input type="text" placeholder="Titre du document" value={newItem.title} onChange={e => setNewItem({...newItem, title: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white text-[12px] outline-none focus:border-cyan-500" />
                        <input type="text" placeholder="Description courte (ex: Cours S1)" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white text-[12px] outline-none focus:border-cyan-500" />
                        <input type="text" placeholder="Coller le lien Google Drive ici" value={newItem.url} onChange={e => setNewItem({...newItem, url: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white text-[12px] outline-none focus:border-cyan-500" />
                        <input type="text" placeholder="Taille (ex: 2.4 MB)" value={newItem.size} onChange={e => setNewItem({...newItem, size: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white text-[12px] outline-none focus:border-cyan-500" />
                      </div>
                    </>
                  )}

                  <button 
                    onClick={generateDataRow}
                    className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-cyan-400 transition-all shadow-xl"
                  >Générer la Ligne de Publication</button>
                </div>
              </div>

              {/* Résultat et Instruction */}
              <div className="bg-slate-900/40 border border-white/10 rounded-[2.5rem] p-10 flex flex-col gap-6">
                <h4 className="text-[11px] font-black text-white/40 uppercase tracking-widest">Instruction de Déploiement</h4>
                <div className="flex-1 bg-black/60 rounded-2xl p-6 font-mono text-[11px] text-cyan-400 break-all select-all border border-cyan-500/20 shadow-inner min-h-[120px] flex items-center justify-center text-center">
                  {generatedRow || "Remplissez le formulaire et cliquez sur générer pour obtenir la ligne à copier dans Google Sheets."}
                </div>
                <div className="bg-cyan-500/5 p-6 rounded-2xl border border-cyan-500/20">
                  <p className="text-[9px] text-cyan-400/60 font-black uppercase leading-relaxed">
                    Copiez cette ligne et collez-la à la fin de votre onglet <span className="underline">{mode === 'category' ? 'Categories' : 'Documents'}</span> dans Google Sheets, puis rafraîchissez le site pour publier.
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'spy' && (
          <div className="space-y-8 animate-in">
             <div className="bg-black/40 rounded-[2rem] border border-white/5 p-6 overflow-x-auto">
                <table className="w-full text-left">
                    <thead>
                        <tr className="text-[8px] uppercase font-black text-white/20 tracking-[0.4em] border-b border-white/10">
                            <th className="pb-4">Identité</th>
                            <th className="pb-4">Action</th>
                            <th className="pb-4 text-right">Instant</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/[0.04]">
                        {activities.map(act => (
                            <tr key={act.id}>
                                <td className="py-4 text-[10px] text-white/80 font-bold">{act.email || 'Explorateur'}</td>
                                <td className="py-4 text-[9px] text-cyan-400 italic">{act.fileName || 'Navigation'}</td>
                                <td className="py-4 text-[8px] text-white/10 font-mono text-right">{act.timestamp}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
             </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-3 animate-in">
            {storageService.getLogs().map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-xl text-[10px] font-mono border border-white/5 flex gap-4">
                   <span className="text-white/10">[{log.timestamp}]</span>
                   <span className="text-cyan-400 font-black uppercase">{log.action}</span>
                   <span className="text-white/60">"{log.details}"</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

export interface Category {
  id: string;
  name: string;
  parentId: string | null;
  icon?: string;
}

export interface AdminAccount {
  id: string;
  username: string;
  role: 'SUPER_MASTER' | 'MASTER' | 'EDITOR';
  lastLogin: string;
}

export interface CloudConfig {
  driveFolderId: string;
  apiKey: string;
  isConnected: boolean;
  lastSync: string;
}

export interface Document {
  id: string;
  title: string;
  description: string;
  categoryId: string;
  fileUrl: string; 
  fileType: 'pdf' | 'docx' | 'image' | 'archive';
  tags: string[];
  downloads: number;
  dateAdded: string;
  size?: string;
}

export interface VisitorActivity {
  id: string;
  type: 'VISIT' | 'DOWNLOAD';
  email?: string;
  fileName?: string;
  timestamp: string;
}

export interface Stats {
  totalVisits: number;
  totalDownloads: number;
  mostViewedCategory?: string;
}

export interface ActivityLog {
  id: string;
  action: 'AUTH' | 'SYSTEM' | 'UPLOAD' | 'DELETE' | 'CONFIG' | 'TRAÇAGE' | 'ACCOUNT';
  timestamp: string;
  details: string;
}

import { Category, Document, AdminAccount, VisitorActivity, ActivityLog } from '../types.ts';
import { INITIAL_CATEGORIES, INITIAL_DOCUMENTS, GOOGLE_SHEET_ID } from '../constants.ts';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  VISITOR_ACTIVITY: 'sp_visitor_spy_logs',
  ACCOUNTS: 'sp_admin_accounts',
  LAST_SYNC: 'sp_last_sync'
};

const parseCSV = (csv: string) => {
  const lines = csv.split('\n');
  if (lines.length === 0) return [];
  const headers = lines[0].split(',').map(h => h.trim().replace(/"/g, ''));
  return lines.slice(1).map(line => {
    const values = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(v => v.trim().replace(/"/g, ''));
    const obj: any = {};
    headers.forEach((header, i) => {
      obj[header] = values[i];
    });
    return obj;
  });
};

export const storageService = {
  fetchFromSheets: async (): Promise<{ categories: Category[], documents: Document[] }> => {
    try {
      const docResponse = await fetch(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/gviz/tq?tqx=out:csv&sheet=Documents`);
      const catResponse = await fetch(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/gviz/tq?tqx=out:csv&sheet=Categories`);

      const docCsv = await docResponse.text();
      const catCsv = await catResponse.text();

      const documents = parseCSV(docCsv).filter(d => d.id).map(d => ({
        ...d,
        downloads: parseInt(d.downloads) || 0,
        tags: d.tags ? d.tags.split('|') : [],
        fileUrl: storageService.optimizeDriveUrl(d.fileUrl)
      }));

      const categories = parseCSV(catCsv).filter(c => c.id).map(c => ({
        ...c,
        parentId: c.parentId === "" || c.parentId === "null" || !c.parentId ? null : c.parentId
      }));

      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(documents));
      localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(categories));
      localStorage.setItem(KEYS.LAST_SYNC, new Date().toISOString());

      return { categories, documents };
    } catch (error) {
      console.error("Erreur Sync:", error);
      return { 
        categories: JSON.parse(localStorage.getItem(KEYS.CATEGORIES) || '[]'), 
        documents: JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]') 
      };
    }
  },

  optimizeDriveUrl: (url: string): string => {
    if (url.includes('drive.google.com')) {
      const idMatch = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
      const id = idMatch ? idMatch[1] : null;
      if (id) return `https://drive.google.com/uc?export=download&id=${id}`;
    }
    return url;
  },

  getAccounts: (): AdminAccount[] => {
    const data = localStorage.getItem(KEYS.ACCOUNTS);
    if (!data) {
      const defaults: AdminAccount[] = [
        { id: '1', username: 'Léon', role: 'MASTER', lastLogin: '' },
        { id: '0', username: 'Astarté', role: 'SUPER_MASTER', lastLogin: '' }
      ];
      localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(defaults));
      return defaults;
    }
    return JSON.parse(data);
  },

  addAccount: (username: string, role: 'MASTER' | 'EDITOR') => {
    const accounts = storageService.getAccounts();
    const newAcc: AdminAccount = {
      id: Date.now().toString(),
      username,
      role,
      lastLogin: 'Jamais'
    };
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify([...accounts, newAcc]));
  },

  removeAccount: (id: string) => {
    const accounts = storageService.getAccounts().filter(a => a.id !== id);
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(accounts));
  },

  getCategories: () => JSON.parse(localStorage.getItem(KEYS.CATEGORIES) || '[]'),
  getDocuments: () => JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]'),
  getLastSync: () => localStorage.getItem(KEYS.LAST_SYNC) || 'Jamais',

  incrementDownload: (id: string) => {
    const docs = storageService.getDocuments();
    const idx = docs.findIndex(d => d.id === id);
    if (idx > -1) {
      docs[idx].downloads += 1;
      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
    }
  },

  logVisit: () => {
    const data = JSON.parse(localStorage.getItem(KEYS.STATS) || '{"totalVisits":0}');
    localStorage.setItem(KEYS.STATS, JSON.stringify({ ...data, totalVisits: data.totalVisits + 1 }));
  },

  logDownload: (email: string, fileName: string) => {
    const activities = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    const newAct = { id: `d-${Date.now()}`, type: 'DOWNLOAD', email, fileName, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newAct, ...activities].slice(0, 500)));
  },

  getVisitorActivities: () => JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]'),
  getLogs: () => JSON.parse(localStorage.getItem(KEYS.LOGS) || '[]'),
  addLog: (action: any, details: string) => {
    const logs = JSON.parse(localStorage.getItem(KEYS.LOGS) || '[]');
    const newLog = { id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.LOGS, JSON.stringify([newLog, ...logs].slice(0, 100)));
  }
};

