                  <path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" />
               </svg>
            </div>
          </div>
          <div className="text-center relative">
            <h1 className="text-4xl md:text-6xl lg:text-7xl font-black tracking-tighter text-white uppercase italic leading-none drop-shadow-[0_0_30px_rgba(0,212,255,0.5)]">
              Success<span className="text-cyan-400">Polaris</span>
            </h1>
            <p className="text-[10px] md:text-[12px] uppercase font-black mt-4 md:mt-6 opacity-40 tracking-[0.8em] md:tracking-[1.2em] group-hover:opacity-100 transition-all duration-1000 text-cyan-400">Majestueuse Voie du Savoir</p>
          </div>
        </div>

        {!isAdminMode && (
          <div className="w-full max-w-lg relative group px-2">
            <div className="absolute -inset-1.5 bg-gradient-to-r from-cyan-500/30 to-indigo-500/30 rounded-[2.5rem] blur opacity-0 group-focus-within:opacity-100 transition-opacity duration-500"></div>
            <input 
              type="text" 
              placeholder="Explorer les archives de SuccessPolaris..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-slate-950/70 border border-white/10 rounded-[2rem] md:rounded-[2.5rem] pl-16 md:pl-20 pr-8 md:pr-10 py-5 md:py-7 text-[13px] md:text-[15px] focus:border-cyan-400/60 outline-none backdrop-blur-3xl transition-all placeholder:text-white/10 text-white font-black relative z-10 shadow-2xl"
            />
          </div>
        )}
      </header>

      <main className="container mx-auto px-6 md:px-12 lg:px-24 relative z-10">
        {isAdminMode ? (
          <div className="space-y-12 animate-in">
            <div className="flex justify-between items-center mb-12 border-b border-white/5 pb-8">
              <div className="flex items-center gap-6">
                 <div className="w-4 h-4 bg-cyan-400 rounded-full shadow-[0_0_25px_#00d4ff] animate-pulse"></div>
                 <h2 className="text-lg md:text-xl font-black uppercase italic tracking-[0.4em] text-white">Console Polaris — {currentAdmin?.username}</h2>
              </div>
              <button 
                onClick={() => { setIsAdminMode(false); setCurrentAdmin(null); }}
                className="bg-white/5 hover:bg-red-500/20 hover:text-red-400 text-white/40 px-8 py-3 rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest border border-white/10 transition-all"
              >Mettre en Veille</button>
            </div>
            <AdminDashboard 
              categories={categories} 
              documents={documents} 
              currentAdmin={currentAdmin}
              onRefresh={syncData} 
            />
          </div>
        ) : (
          <div className="space-y-16 md:space-y-24">
            <nav className="flex items-center gap-3 md:gap-5 overflow-x-auto no-scrollbar py-4 md:py-6 px-6 md:px-10 bg-slate-950/60 rounded-[2.5rem] md:rounded-[3rem] border border-white/5 backdrop-blur-3xl">
              <button onClick={() => navigateTo(null)} className={`px-8 md:px-12 py-3 md:py-4 rounded-[1.2rem] md:rounded-[1.5rem] text-[10px] md:text-[12px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${navigationPath.length === 0 ? 'bg-cyan-400 text-slate-950' : 'text-white/20 hover:text-white'}`}>Racine Polaris</button>
              {navigationPath.map((cat, i) => (
                <React.Fragment key={cat.id}>
                  <div className="w-1.5 h-1.5 bg-cyan-400/20 rounded-full shrink-0"></div>
                  <button onClick={() => goBackTo(i)} className={`px-8 md:px-12 py-3 md:py-4 rounded-[1.2rem] md:rounded-[1.5rem] text-[10px] md:text-[12px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${i === navigationPath.length - 1 ? 'bg-white text-slate-950' : 'text-white/20 hover:text-white'}`}>{cat.name}</button>
                </React.Fragment>
              ))}
            </nav>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 md:gap-20">
              {!searchQuery && (
                <div className="lg:col-span-4 space-y-6 md:space-y-10">
                  <h3 className="text-white/20 text-[9px] md:text-[11px] font-black uppercase tracking-[1em] mb-10 flex items-center gap-4 pl-3">
                    <div className="w-2 h-2 bg-cyan-500 rounded-full animate-ping"></div> Secteurs
                  </h3>
                  <div className="grid grid-cols-1 gap-4 md:gap-6">
                    {currentLevelCategories.map(cat => (
                      <button key={cat.id} onClick={() => navigateTo(cat)} className="w-full flex items-center justify-between p-8 md:p-10 bg-slate-900/40 border border-white/5 hover:border-cyan-500/40 rounded-[2.5rem] group transition-all duration-700 hover:bg-cyan-500/5 backdrop-blur-md">
                        <div className="flex items-center gap-6 md:gap-8">
                          <span className="text-3xl opacity-50 group-hover:opacity-100 transition-all">{cat.icon || '🪐'}</span>
                          <span className="text-[15px] font-black text-white/90 group-hover:text-cyan-400 transition-colors uppercase tracking-tighter block leading-none">{cat.name}</span>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div className={`${searchQuery ? 'lg:col-span-12' : 'lg:col-span-8'} space-y-12`}>
                <h3 className="text-white/20 text-[9px] md:text-[11px] font-black uppercase tracking-[1em] mb-10 flex items-center gap-4 pl-3">
                   <div className="w-2 h-2 bg-indigo-500 rounded-full"></div> Archives
                </h3>
                {currentLevelDocuments.length > 0 ? (
                  <div className={`grid grid-cols-1 ${searchQuery ? 'sm:grid-cols-2 lg:grid-cols-3' : 'sm:grid-cols-2'} gap-8 md:gap-12`}>
                    {currentLevelDocuments.map(doc => (
                      <DocumentCard key={doc.id} doc={doc} onDownload={initiateDownload} />
                    ))}
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center py-32 md:py-48 bg-slate-900/10 rounded-[4rem] border border-dashed border-white/5">
                    <p className="text-white/10 text-[13px] font-black uppercase tracking-[1.5em]">Horizon vide</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full py-4 px-6 md:px-12 bg-slate-950/90 backdrop-blur-3xl border-t border-white/5 flex flex-col sm:flex-row items-center justify-between z-[1000] gap-4">
        <div className="flex items-center gap-4">
          <div className="w-2 h-2 bg-cyan-500 rounded-full animate-pulse"></div>
          <p className="text-[8px] md:text-[9px] text-white/30 font-black uppercase tracking-[0.4em]">SuccessPolaris — Palace v1.0.2</p>
        </div>
        <div className="flex items-center gap-4 select-none">
          <p className="text-[8px] text-white/20 font-black uppercase tracking-widest">
            CRÉÉ PAR <span onClick={() => setShowAdminLogin(true)} className="hover:text-cyan-400 cursor-pointer transition-colors duration-500">ASTARTÉ</span> — MEMBRE DE NEMESIS
          </p>
        </div>
      </footer>

      {showEmailModal && (
        <div className="fixed inset-0 z-[6000] flex items-center justify-center p-6 bg-slate-950/98 backdrop-blur-3xl animate-in">
          <div className="max-w-[420px] w-full p-12 md:p-16 bg-slate-900/60 border border-white/15 rounded-[4rem] relative shadow-3xl">
            <button onClick={() => setShowEmailModal(false)} className="absolute top-10 right-10 text-white/20 hover:text-white text-2xl">×</button>
            <div className="text-center mb-10">
              <h3 className="text-md font-black text-white uppercase italic tracking-[0.5em] mb-3">Identification Requise</h3>
              <p className="text-[9px] text-white/30 font-bold uppercase">Format d'email vérifié par Polaris</p>
            </div>
            <form onSubmit={handleIdentityConfirm} className="space-y-10">
              <div className="bg-cyan-500/5 p-6 rounded-[2.5rem] border border-cyan-500/20 text-center font-black text-cyan-400">{pendingDoc?.title}</div>
              <input type="email" required placeholder="votre@email.com" value={userEmail} onChange={e => { setUserEmail(e.target.value); setEmailError(''); }} className={`w-full bg-black/70 border ${emailError ? 'border-red-500' : 'border-white/10'} rounded-[1.5rem] px-8 py-5 text-white outline-none focus:border-cyan-400 font-black text-center`} />
              {emailError && <p className="text-center text-red-500 text-[9px] font-black uppercase">{emailError}</p>}
              <button type="submit" className="w-full bg-cyan-400 hover:bg-white text-slate-950 font-black py-6 rounded-[1.5rem] uppercase text-[11px] tracking-[0.5em] transition-all">Télécharger l'Archive</button>
            </form>
          </div>
        </div>
      )}

      {showAdminLogin && (
        <div className="fixed inset-0 z-[5000] flex items-center justify-center p-6 bg-black/98 backdrop-blur-3xl animate-in">
          <div className="max-w-[380px] w-full p-12 md:p-16 bg-slate-900/50 border border-white/15 rounded-[4rem] relative">
            <button onClick={() => setShowAdminLogin(false)} className="absolute top-10 right-10 text-white/20 hover:text-white text-2xl">×</button>
            <form onSubmit={handleAdminLogin} className="space-y-8">
              <div className="text-center">
                <div className="w-16 h-16 bg-cyan-500/10 rounded-3xl flex items-center justify-center mx-auto mb-6 border border-cyan-500/20">
                  <i className="fas fa-fingerprint text-cyan-400 text-2xl"></i>
                </div>
                <h3 className="text-white font-black uppercase tracking-[0.4em] mb-10 italic">Console Nemesis</h3>
              </div>
              <input type="text" placeholder="Utilisateur" value={adminUsername} onChange={e => setAdminUsername(e.target.value)} className="w-full bg-black/80 border border-white/10 rounded-[1.5rem] px-8 py-6 text-white outline-none focus:border-cyan-400 text-center font-black" />
              <input type="password" placeholder="Clé Stellaire" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} className="w-full bg-black/80 border border-white/10 rounded-[1.5rem] px-8 py-6 text-white outline-none focus:border-cyan-400 text-center font-black" />
              {loginError && <p className="text-center text-red-500 text-[9px] font-black uppercase animate-pulse">Clé Invalide</p>}
              <button type="submit" className="w-full bg-white text-slate-950 font-black py-6 rounded-[1.5rem] uppercase tracking-widest hover:bg-cyan-400 transition-all">Éveil du Système</button>
            </form>
          </div>
        </div>
      )}

      {isSyncing && (
        <div className="fixed inset-0 z-[10000] flex flex-col items-center justify-center bg-slate-950/98 backdrop-blur-3xl">
           <div className="w-20 h-20 border-4 border-cyan-500/10 border-t-cyan-500 rounded-full animate-spin"></div>
           <p className="text-cyan-400 text-[10px] font-black uppercase tracking-[1em] mt-10 animate-pulse">Synchronisation Cloud...</p>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, VisitorActivity, AdminAccount } from '../types.ts';
import { GOOGLE_SHEET_ID } from '../constants.ts';

interface AdminDashboardProps {
  categories: Category[];
  documents: Document[];
  currentAdmin: AdminAccount | null;
  onRefresh?: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ categories, documents, currentAdmin, onRefresh }) => {
  const [activeTab, setActiveTab] = useState<'status' | 'architect' | 'spy' | 'keys' | 'logs'>('status');
  const [activities, setActivities] = useState<VisitorActivity[]>([]);
  const [accounts, setAccounts] = useState<AdminAccount[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);

  // Wizard state
  const [publishStep, setPublishStep] = useState(0);
  const [mode, setMode] = useState<'category' | 'document'>('document');

  // For keys management
  const [newKeyName, setNewKeyName] = useState('');

  // Form states
  const [parentSelection, setParentSelection] = useState<string>('root');
  const [newItem, setNewItem] = useState({
    name: '',
    icon: '📁',
    title: '',
    description: '',
    url: '',
    size: '1.0 MB',
    tags: 'Cours|Révision'
  });

  const [generatedRow, setGeneratedRow] = useState<string>('');

  useEffect(() => {
    setActivities(storageService.getVisitorActivities());
    setAccounts(storageService.getAccounts());
  }, []);

  const handleManualSync = async () => {
    setIsSyncing(true);
    if (onRefresh) await onRefresh();
    setIsSyncing(false);
  };

  const handleAddKey = () => {
    if (!newKeyName) return;
    storageService.addAccount(newKeyName, 'MASTER');
    setAccounts(storageService.getAccounts());
    setNewKeyName('');
    storageService.addLog('ACCOUNT', `Nouvelle clé créée pour ${newKeyName}`);
  };

  const handleRemoveKey = (id: string) => {
    if (id === '0') return; 
    storageService.removeAccount(id);
    setAccounts(storageService.getAccounts());
    storageService.addLog('ACCOUNT', `Clé révoquée (ID: ${id})`);
  };

  const generateDataRow = () => {
    const id = Math.random().toString(36).substr(2, 9);
    const parentId = parentSelection === 'root' ? '' : parentSelection;

    if (mode === 'category') {
      setGeneratedRow(`${id},"${newItem.name}","${parentId}","${newItem.icon}"`);
    } else {
      const date = new Date().toISOString();
      setGeneratedRow(`${id},"${newItem.title}","${newItem.description}","${parentId}","${newItem.url.trim()}","pdf","${newItem.tags}",0,"${date}","${newItem.size}"`);
    }
    setPublishStep(mode === 'category' ? 4 : 6);
  };

  const resetWizard = () => {
    setPublishStep(0);
    setGeneratedRow('');
    setNewItem({
      name: '',
      icon: '📁',
      title: '',
      description: '',
      url: '',
      size: '1.0 MB',
      tags: 'Cours|Révision'
    });
  };

  return (
    <div className="bg-slate-950/40 rounded-[2rem] md:rounded-[3rem] border border-white/5 overflow-hidden backdrop-blur-3xl shadow-2xl flex flex-col min-h-[600px]">
      {/* Navigation Tabs */}
      <div className="flex bg-black/60 overflow-x-auto no-scrollbar border-b border-white/10">
        {[
          { id: 'status', label: 'État Cloud', icon: '☁️' },
          { id: 'architect', label: 'Architecte', icon: '🏛️' },
          { id: 'spy', label: 'Espionnage', icon: '👁️' },
          ...(currentAdmin?.role === 'SUPER_MASTER' ? [{ id: 'keys', label: 'Clés Stellaires', icon: '🔑' }] : []),
          { id: 'logs', label: 'Système', icon: '📟' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => { setActiveTab(tab.id as any); resetWizard(); }}
            className={`flex-1 py-6 px-8 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap flex items-center justify-center gap-3 ${
              activeTab === tab.id ? 'border-cyan-500 bg-cyan-500/5 text-white' : 'border-transparent text-white/30 hover:text-white'
            }`}
          >
            <span className="text-sm">{tab.icon}</span>
            {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-12 flex-1 flex flex-col overflow-y-auto max-h-[700px] no-scrollbar">
        {activeTab === 'status' && (
          <div className="space-y-8 animate-in">
            <div className="bg-gradient-to-br from-slate-900 to-black p-10 rounded-[2.5rem] border border-white/10 shadow-xl">
               <h3 className="text-xl font-black text-white uppercase italic mb-6">Noyau de Données</h3>
               <p className="text-white/40 text-[11px] uppercase font-bold tracking-[0.3em] mb-8 leading-loose">
                 La connexion avec la matrice Google Sheets est active. Utilisez le bouton ci-dessous pour modifier directement les constellations de données.
               </p>
               <div className="flex flex-col sm:flex-row gap-4">
                  <button onClick={() => window.open(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/edit`, '_blank')} className="flex-1 bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-lg">Ouvrir la Matrice Sheets</button>
                  <button onClick={handleManualSync} disabled={isSyncing} className="flex-1 bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-500 hover:text-slate-950 transition-all">{isSyncing ? 'Synchronisation...' : 'Forcer la Mise à Jour'}</button>
               </div>
            </div>
          </div>
        )}

        {activeTab === 'architect' && (
          <div className="max-w-3xl mx-auto w-full space-y-12 animate-in py-6">
            <div className="text-center space-y-4">
              <h3 className="text-2xl font-black text-white uppercase italic tracking-tighter">Assistant de Publication Polaris</h3>
              <p className="text-[10px] text-white/30 font-black uppercase tracking-[0.5em]">Étape {publishStep + 1} sur {mode === 'document' ? 7 : 5}</p>
            </div>

            {/* Wizard Steps Container */}
            <div className="bg-white/[0.03] border border-white/10 rounded-[3rem] p-10 md:p-16 relative overflow-hidden">
               {/* Progress Bar */}
               <div className="absolute top-0 left-0 h-1 bg-cyan-500 transition-all duration-700" style={{ width: `${((publishStep + 1) / (mode === 'document' ? 7 : 5)) * 100}%` }}></div>

               {/* Step 0: Choice */}
               {publishStep === 0 && (
                 <div className="space-y-10 animate-in">
                   <p className="text-center text-white/60 font-medium italic">"Que souhaitez-vous matérialiser dans votre galaxie ?"</p>
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                     <button onClick={() => { setMode('document'); setPublishStep(1); }} className="bg-indigo-500/10 border border-indigo-500/30 p-12 rounded-[2.5rem] hover:bg-indigo-500 transition-all group">
                        <span className="block text-4xl mb-4">📄</span>
                        <span className="block text-white font-black uppercase tracking-widest text-[11px] group-hover:scale-110 transition-transform">Un Nouveau Document</span>
                     </button>
                     <button onClick={() => { setMode('category'); setPublishStep(1); }} className="bg-cyan-500/10 border border-cyan-500/30 p-12 rounded-[2.5rem] hover:bg-cyan-500 transition-all group">
                        <span className="block text-4xl mb-4">📁</span>
                        <span className="block text-white font-black uppercase tracking-widest text-[11px] group-hover:scale-110 transition-transform">Une Sous-Catégorie</span>
                     </button>
                   </div>
                 </div>
               )}

               {/* Document Wizard */}
               {mode === 'document' && publishStep > 0 && (
                 <div className="space-y-10">
                    {publishStep === 1 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 1 : Source Stellaire</h4>
                        <div className="bg-indigo-500/10 p-6 rounded-3xl border border-indigo-500/20 text-center space-y-4">
                          <p className="text-[10px] text-indigo-300 font-bold uppercase italic">Accédez à votre archive et copiez le lien de partage (Tous avec le lien)</p>
                          <button onClick={() => window.open('https://drive.google.com', '_blank')} className="bg-indigo-500 text-white px-8 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest hover:scale-105 transition-all">Ouvrir Google Drive</button>
                        </div>
                        <input type="text" autoFocus placeholder="Collez le lien Google Drive ici..." value={newItem.url} onChange={e => setNewItem({...newItem, url: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center shadow-inner" />
                        <button onClick={() => newItem.url && setPublishStep(2)} disabled={!newItem.url} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.3em] hover:bg-cyan-400 disabled:opacity-20 transition-all">OK - Étape Suivante</button>
                      </div>
                    )}

                    {publishStep === 2 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 2 : Identité du Document</h4>
                        <input type="text" autoFocus placeholder="Saisissez le titre du fichier..." value={newItem.title} onChange={e => setNewItem({...newItem, title: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center shadow-inner" />
                        <button onClick={() => newItem.title && setPublishStep(3)} disabled={!newItem.title} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.3em] hover:bg-cyan-400 disabled:opacity-20 transition-all">OK - Valider le Titre</button>
                        <button onClick={() => setPublishStep(1)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 3 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 3 : Essence / Description</h4>
                        <textarea autoFocus placeholder="Que contient ce document ? (Ex: Cours de S1, Fiche de révision...)" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} className="w-full h-32 bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium shadow-inner resize-none" />
                        <button onClick={() => newItem.description && setPublishStep(4)} disabled={!newItem.description} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.3em] hover:bg-cyan-400 disabled:opacity-20 transition-all">OK - Valider la Description</button>
                        <button onClick={() => setPublishStep(2)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 4 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 4 : Ancrage (Catégorie)</h4>
                        <p className="text-center text-[10px] text-white/40 uppercase font-black italic">"Où ce savoir doit-il se reposer ?"</p>
                        <select value={parentSelection} onChange={(e) => setParentSelection(e.target.value)} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 appearance-none text-center cursor-pointer">
                          <option value="root">Racine (Catégorie Principale)</option>
                          {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <button onClick={() => setPublishStep(5)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.3em] hover:bg-cyan-400 transition-all">OK - Étape Suivante</button>
                        <button onClick={() => setPublishStep(3)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 5 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 5 : Magnitude (Taille)</h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                           <input type="text" placeholder="Taille (Ex: 1.5 MB)" value={newItem.size} onChange={e => setNewItem({...newItem, size: e.target.value})} className="bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 text-center" />
                           <input type="text" placeholder="Tags (Ex: Cours|PDF)" value={newItem.tags} onChange={e => setNewItem({...newItem, tags: e.target.value})} className="bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 text-center" />
                        </div>
                        <button onClick={generateDataRow} className="w-full bg-cyan-500 text-slate-950 py-6 rounded-2xl text-[11px] font-black uppercase tracking-[0.5em] hover:bg-white transition-all shadow-2xl">PUBLIER DANS LA MATRICE</button>
                        <button onClick={() => setPublishStep(4)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}
                 </div>
               )}

               {/* Category Wizard */}
               {mode === 'category' && publishStep > 0 && (
                 <div className="space-y-10">
                    {publishStep === 1 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Nom de la Constellation</h4>
                        <input type="text" autoFocus placeholder="Saisissez le nom de la catégorie..." value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center shadow-inner" />
                        <button onClick={() => newItem.name && setPublishStep(2)} disabled={!newItem.name} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.3em] hover:bg-cyan-400 transition-all">OK - Étape Suivante</button>
                        <button onClick={() => setPublishStep(0)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Annuler</button>
                      </div>
                    )}

                    {publishStep === 2 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Aura Visuelle (Emoji Icône)</h4>
                        <input type="text" autoFocus placeholder="Symbole (Ex: 📘, ⚡, 🧬)" value={newItem.icon} onChange={e => setNewItem({...newItem, icon: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-3xl outline-none focus:border-cyan-400 font-medium text-center shadow-inner" />
                        <button onClick={() => setPublishStep(3)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.3em] hover:bg-cyan-400 transition-all">OK - Valider l'icône</button>
                        <button onClick={() => setPublishStep(1)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 3 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Ancrage Parent</h4>
                        <select value={parentSelection} onChange={(e) => setParentSelection(e.target.value)} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 appearance-none text-center cursor-pointer">
                          <option value="root">Racine (Niveau 1)</option>
                          {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <button onClick={generateDataRow} className="w-full bg-cyan-500 text-slate-950 py-6 rounded-2xl text-[11px] font-black uppercase tracking-[0.5em] hover:bg-white transition-all shadow-2xl">MATÉRIALISER LA CATÉGORIE</button>
                        <button onClick={() => setPublishStep(2)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}
                 </div>
               )}

               {/* Final Deployment (The Row) */}
               {((mode === 'document' && publishStep === 6) || (mode === 'category' && publishStep === 4)) && (
                 <div className="space-y-10 animate-in text-center">
                    <div className="w-20 h-20 bg-emerald-500/20 rounded-full flex items-center justify-center mx-auto border border-emerald-500/30 animate-pulse">
                       <i className="fas fa-check text-emerald-400 text-2xl"></i>
                    </div>
                    <div className="space-y-2">
                       <h4 className="text-white font-black uppercase tracking-widest text-lg">Éveil de la Donnée</h4>
                       <p className="text-[10px] text-white/30 font-black uppercase tracking-widest italic">Copiez cette ligne et insérez-la dans Google Sheets</p>
                    </div>

                    <div className="bg-black/60 rounded-2xl p-8 border border-cyan-500/30 font-mono text-cyan-400 break-all select-all text-[11px] shadow-inner relative group">
                        <div className="absolute top-2 right-4 text-[8px] text-white/10 uppercase font-black">Cliquez pour copier tout</div>
                        {generatedRow}
                    </div>

                    <div className="flex gap-4">
                       <button onClick={resetWizard} className="flex-1 bg-white/5 text-white/40 py-5 rounded-2xl text-[10px] font-black uppercase border border-white/5 hover:bg-white/10 transition-all">Nouveau</button>
                       <button onClick={() => window.open(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/edit`, '_blank')} className="flex-[2] bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-lg">Ouvrir Sheets pour coller</button>
                    </div>
                 </div>
               )}
            </div>
          </div>
        )}

        {activeTab === 'keys' && currentAdmin?.role === 'SUPER_MASTER' && (
          <div className="space-y-10 animate-in">
            <div className="bg-slate-900/40 border border-white/10 rounded-[2.5rem] p-8">
               <h3 className="text-[12px] font-black text-white uppercase italic mb-6 text-cyan-400 tracking-widest">Forge de Nouvelles Clés</h3>
               <div className="flex gap-4">
                  <input type="text" placeholder="Nom de la nouvelle clé" value={newKeyName} onChange={e => setNewKeyName(e.target.value)} className="flex-1 bg-black/60 border border-white/10 rounded-2xl p-5 text-white text-[12px] outline-none" />
                  <button onClick={handleAddKey} className="bg-white text-slate-950 px-10 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all">Forger</button>
               </div>
            </div>

            <div className="space-y-4">
               <h4 className="text-[10px] font-black text-white/20 uppercase tracking-widest pl-4">Réseau de Clés Actives</h4>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {accounts.map(acc => (
                    <div key={acc.id} className="bg-white/[0.03] p-6 rounded-3xl border border-white/5 flex items-center justify-between group">
                       <div>
                          <p className={`text-[13px] font-black ${acc.role === 'SUPER_MASTER' ? 'text-cyan-400' : 'text-white'}`}>{acc.username}</p>
                          <p className="text-[8px] text-white/30 uppercase font-black tracking-widest">{acc.role}</p>
                       </div>
                       {acc.role !== 'SUPER_MASTER' && (
                         <button onClick={() => handleRemoveKey(acc.id)} className="bg-red-500/10 text-red-500 p-4 rounded-2xl hover:bg-red-500 hover:text-white transition-all">
                            <i className="fas fa-trash-alt text-[10px]"></i>
                         </button>
                       )}
                    </div>
                  ))}
               </div>
            </div>
          </div>
        )}

        {activeTab === 'spy' && (
          <div className="space-y-8 animate-in">
             <div className="bg-black/40 rounded-[2rem] border border-white/5 p-6 overflow-x-auto">
                <table className="w-full text-left">
                    <thead>
                        <tr className="text-[8px] uppercase font-black text-white/20 tracking-[0.4em] border-b border-white/10">
                            <th className="pb-4">Identité</th>
                            <th className="pb-4">Action</th>
                            <th className="pb-4 text-right">Instant</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/[0.04]">
                        {activities.map(act => (
                            <tr key={act.id}>
                                <td className="py-4 text-[10px] text-white/80 font-bold">{act.email || 'Explorateur'}</td>
                                <td className="py-4 text-[9px] text-cyan-400 italic">{act.fileName || 'Navigation'}</td>
                                <td className="py-4 text-[8px] text-white/10 font-mono text-right">{act.timestamp}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
             </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-3 animate-in">
            {storageService.getLogs().map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-xl text-[10px] font-mono border border-white/5 flex gap-4">
                   <span className="text-white/10">[{log.timestamp}]</span>
                   <span className="text-cyan-400 font-black uppercase">{log.action}</span>
                   <span className="text-white/60">"{log.details}"</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

import { Document, Category } from './types.ts';

export const THEME = {
  deepBlue: '#050b18',
  electricCyan: '#00d4ff',
  glacialWhite: '#e6f1ff',
  vividViolet: '#7b4dff',
  glassBorder: 'rgba(255, 255, 255, 0.05)',
  glassBg: 'rgba(15, 23, 42, 0.6)'
};

// --- CONFIGURATION DYNAMIQUE ---
// ID Google Sheets réel connecté
export const GOOGLE_SHEET_ID = '1fg-tStXc8E04WLqkHxDfrEJR7yf6ix0uzL4y52HF0k0'; 

export const INITIAL_CATEGORIES: Category[] = [];
export const INITIAL_DOCUMENTS: Document[] = [];

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, VisitorActivity, AdminAccount } from '../types.ts';
import { GOOGLE_SHEET_ID } from '../constants.ts';

interface AdminDashboardProps {
  categories: Category[];
  documents: Document[];
  currentAdmin: AdminAccount | null;
  onRefresh?: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ categories, documents, currentAdmin, onRefresh }) => {
  const [activeTab, setActiveTab] = useState<'status' | 'architect' | 'spy' | 'keys' | 'logs'>('status');
  const [activities, setActivities] = useState<VisitorActivity[]>([]);
  const [accounts, setAccounts] = useState<AdminAccount[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);

  // Wizard state (Step-by-step logic)
  const [publishStep, setPublishStep] = useState(0);
  const [mode, setMode] = useState<'category' | 'document'>('document');

  // For keys management
  const [newKeyName, setNewKeyName] = useState('');

  // Form states
  const [parentSelection, setParentSelection] = useState<string>('root');
  const [newItem, setNewItem] = useState({
    name: '',
    icon: '📁',
    title: '',
    description: '',
    url: '',
    size: '1.0 MB',
    tags: 'Cours|Révision'
  });

  const [generatedRow, setGeneratedRow] = useState<string>('');

  useEffect(() => {
    setActivities(storageService.getVisitorActivities());
    setAccounts(storageService.getAccounts());
  }, []);

  const handleManualSync = async () => {
    setIsSyncing(true);
    if (onRefresh) await onRefresh();
    setIsSyncing(false);
  };

  const handleAddKey = () => {
    if (!newKeyName) return;
    storageService.addAccount(newKeyName, 'MASTER');
    setAccounts(storageService.getAccounts());
    setNewKeyName('');
    storageService.addLog('ACCOUNT', `Nouvelle clé créée pour ${newKeyName}`);
  };

  const handleRemoveKey = (id: string) => {
    if (id === '0') return; 
    storageService.removeAccount(id);
    setAccounts(storageService.getAccounts());
    storageService.addLog('ACCOUNT', `Clé révoquée (ID: ${id})`);
  };

  const generateDataRow = () => {
    const id = Math.random().toString(36).substr(2, 9);
    const parentId = parentSelection === 'root' ? '' : parentSelection;

    if (mode === 'category') {
      setGeneratedRow(`${id},"${newItem.name}","${parentId}","${newItem.icon}"`);
      setPublishStep(4); // Step finish for category
    } else {
      const date = new Date().toISOString();
      setGeneratedRow(`${id},"${newItem.title}","${newItem.description}","${parentId}","${newItem.url.trim()}","pdf","${newItem.tags}",0,"${date}","${newItem.size}"`);
      setPublishStep(6); // Step finish for document
    }
  };

  const resetWizard = () => {
    setPublishStep(0);
    setGeneratedRow('');
    setNewItem({
      name: '',
      icon: '📁',
      title: '',
      description: '',
      url: '',
      size: '1.0 MB',
      tags: 'Cours|Révision'
    });
  };

  return (
    <div className="bg-slate-950/40 rounded-[2rem] md:rounded-[3rem] border border-white/5 overflow-hidden backdrop-blur-3xl shadow-2xl flex flex-col min-h-[600px]">
      <div className="flex bg-black/60 overflow-x-auto no-scrollbar border-b border-white/10">
        {[
          { id: 'status', label: 'État Cloud', icon: '☁️' },
          { id: 'architect', label: 'Architecte', icon: '🏛️' },
          { id: 'spy', label: 'Espionnage', icon: '👁️' },
          ...(currentAdmin?.role === 'SUPER_MASTER' ? [{ id: 'keys', label: 'Clés Stellaires', icon: '🔑' }] : []),
          { id: 'logs', label: 'Système', icon: '📟' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => { setActiveTab(tab.id as any); resetWizard(); }}
            className={`flex-1 py-6 px-8 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap flex items-center justify-center gap-3 ${
              activeTab === tab.id ? 'border-cyan-500 bg-cyan-500/5 text-white' : 'border-transparent text-white/30 hover:text-white'
            }`}
          >
            <span className="text-sm">{tab.icon}</span>
            {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-12 flex-1 flex flex-col overflow-y-auto max-h-[700px] no-scrollbar">
        {activeTab === 'status' && (
          <div className="space-y-8 animate-in">
            <div className="bg-gradient-to-br from-slate-900 to-black p-10 rounded-[2.5rem] border border-white/10 shadow-xl">
               <h3 className="text-xl font-black text-white uppercase italic mb-6">Noyau de Données</h3>
               <p className="text-white/40 text-[11px] uppercase font-bold tracking-[0.3em] mb-8 leading-loose">
                 Connecté à l'ID : <span className="text-cyan-400 font-mono">{GOOGLE_SHEET_ID}</span>
               </p>
               <div className="flex flex-col sm:flex-row gap-4">
                  <button onClick={() => window.open(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/edit`, '_blank')} className="flex-1 bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-lg">Ouvrir la Matrice Sheets</button>
                  <button onClick={handleManualSync} disabled={isSyncing} className="flex-1 bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-500 hover:text-slate-950 transition-all">{isSyncing ? 'Synchronisation...' : 'Forcer la Mise à Jour'}</button>
               </div>
            </div>
          </div>
        )}

        {activeTab === 'architect' && (
          <div className="max-w-3xl mx-auto w-full space-y-12 animate-in py-6">
            <div className="text-center space-y-4">
              <h3 className="text-2xl font-black text-white uppercase italic tracking-tighter">Assistant de Publication Polaris</h3>
              <p className="text-[10px] text-white/30 font-black uppercase tracking-[0.5em]">Étape {publishStep + 1} / {mode === 'document' ? 7 : 5}</p>
            </div>

            <div className="bg-white/[0.03] border border-white/10 rounded-[3rem] p-10 md:p-16 relative overflow-hidden">
               <div className="absolute top-0 left-0 h-1 bg-cyan-500 transition-all duration-700" style={{ width: `${((publishStep + 1) / (mode === 'document' ? 7 : 5)) * 100}%` }}></div>

               {publishStep === 0 && (
                 <div className="space-y-10 animate-in">
                   <p className="text-center text-white/60 font-medium italic">"Quel type de savoir voulez-vous matérialiser ?"</p>
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                     <button onClick={() => { setMode('document'); setPublishStep(1); }} className="bg-indigo-500/10 border border-indigo-500/30 p-12 rounded-[2.5rem] hover:bg-indigo-500 transition-all group">
                        <span className="block text-4xl mb-4">📄</span>
                        <span className="block text-white font-black uppercase tracking-widest text-[11px] group-hover:scale-110 transition-transform">Nouveau Document</span>
                     </button>
                     <button onClick={() => { setMode('category'); setPublishStep(1); }} className="bg-cyan-500/10 border border-cyan-500/30 p-12 rounded-[2.5rem] hover:bg-cyan-500 transition-all group">
                        <span className="block text-4xl mb-4">📁</span>
                        <span className="block text-white font-black uppercase tracking-widest text-[11px] group-hover:scale-110 transition-transform">Sous-Catégorie</span>
                     </button>
                   </div>
                 </div>
               )}

               {mode === 'document' && publishStep > 0 && (
                 <div className="space-y-10">
                    {publishStep === 1 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 1 : Lien du Fichier</h4>
                        <button onClick={() => window.open('https://drive.google.com', '_blank')} className="w-full bg-white/5 text-indigo-400 py-3 rounded-xl text-[9px] font-black uppercase border border-white/10 mb-4">Ouvrir Google Drive</button>
                        <input type="text" autoFocus placeholder="Collez le lien Google Drive..." value={newItem.url} onChange={e => setNewItem({...newItem, url: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center" />
                        <button onClick={() => newItem.url && setPublishStep(2)} disabled={!newItem.url} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 disabled:opacity-20 transition-all">OK</button>
                      </div>
                    )}

                    {publishStep === 2 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 2 : Nom du Fichier</h4>
                        <input type="text" autoFocus placeholder="Saisissez le titre..." value={newItem.title} onChange={e => setNewItem({...newItem, title: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center" />
                        <button onClick={() => newItem.title && setPublishStep(3)} disabled={!newItem.title} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 disabled:opacity-20 transition-all">OK</button>
                        <button onClick={() => setPublishStep(1)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 3 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 3 : Description</h4>
                        <textarea autoFocus placeholder="Quelques mots sur ce contenu..." value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} className="w-full h-32 bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium resize-none shadow-inner" />
                        <button onClick={() => newItem.description && setPublishStep(4)} disabled={!newItem.description} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 disabled:opacity-20 transition-all">OK</button>
                        <button onClick={() => setPublishStep(2)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 4 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 4 : Secteur (Catégorie)</h4>
                        <select value={parentSelection} onChange={(e) => setParentSelection(e.target.value)} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 text-center appearance-none">
                          <option value="root">Racine</option>
                          {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <button onClick={() => setPublishStep(5)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all">OK</button>
                        <button onClick={() => setPublishStep(3)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 5 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 5 : Magnitude (Taille)</h4>
                        <input type="text" placeholder="Ex: 2.4 MB" value={newItem.size} onChange={e => setNewItem({...newItem, size: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 text-center" />
                        <button onClick={generateDataRow} className="w-full bg-cyan-500 text-slate-950 py-6 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-white transition-all shadow-2xl">FINALISER LA PUBLICATION</button>
                        <button onClick={() => setPublishStep(4)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}
                 </div>
               )}

               {mode === 'category' && publishStep > 0 && (
                 <div className="space-y-10">
                    {publishStep === 1 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Nom de la Catégorie</h4>
                        <input type="text" autoFocus placeholder="Saisissez le nom..." value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center" />
                        <button onClick={() => newItem.name && setPublishStep(2)} disabled={!newItem.name} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all">OK</button>
                        <button onClick={() => setPublishStep(0)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Annuler</button>
                      </div>
                    )}

                    {publishStep === 2 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Icône (Emoji)</h4>
                        <input type="text" autoFocus placeholder="⚡, 📚, 🎨..." value={newItem.icon} onChange={e => setNewItem({...newItem, icon: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-4xl outline-none focus:border-cyan-400 text-center" />
                        <button onClick={() => setPublishStep(3)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all">OK</button>
                        <button onClick={() => setPublishStep(1)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}

                    {publishStep === 3 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Positionnement</h4>
                        <select value={parentSelection} onChange={(e) => setParentSelection(e.target.value)} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 text-center appearance-none">
                          <option value="root">Niveau Racine</option>
                          {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <button onClick={generateDataRow} className="w-full bg-cyan-500 text-slate-950 py-6 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-white transition-all shadow-2xl">PUBLIER LA CATÉGORIE</button>
                        <button onClick={() => setPublishStep(2)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour</button>
                      </div>
                    )}
                 </div>
               )}

               {((mode === 'document' && publishStep === 6) || (mode === 'category' && publishStep === 4)) && (
                 <div className="space-y-10 animate-in text-center">
                    <div className="w-20 h-20 bg-emerald-500/20 rounded-full flex items-center justify-center mx-auto border border-emerald-500/30">
                       <i className="fas fa-check text-emerald-400 text-2xl"></i>
                    </div>
                    <div className="space-y-2">
                       <h4 className="text-white font-black uppercase tracking-widest text-lg">Donnée Prête</h4>
                       <p className="text-[10px] text-white/30 font-black uppercase italic">Copiez la ligne ci-dessous et collez-la dans votre Google Sheet</p>
                    </div>

                    <div className="bg-black/60 rounded-2xl p-8 border border-cyan-500/30 font-mono text-cyan-400 break-all select-all text-[11px] shadow-inner">
                        {generatedRow}
                    </div>

                    <div className="flex gap-4">
                       <button onClick={resetWizard} className="flex-1 bg-white/5 text-white/40 py-5 rounded-2xl text-[10px] font-black uppercase border border-white/10">Recommencer</button>
                       <button onClick={() => window.open(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/edit`, '_blank')} className="flex-[2] bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all">Ouvrir et Coller</button>
                    </div>
                 </div>
               )}
            </div>
          </div>
        )}

        {activeTab === 'keys' && currentAdmin?.role === 'SUPER_MASTER' && (
          <div className="space-y-10 animate-in">
            <div className="bg-slate-900/40 border border-white/10 rounded-[2.5rem] p-8">
               <h3 className="text-[12px] font-black text-white uppercase italic mb-6 text-cyan-400 tracking-widest">Forge Stellaire</h3>
               <div className="flex gap-4">
                  <input type="text" placeholder="Nom de la clé..." value={newKeyName} onChange={e => setNewKeyName(e.target.value)} className="flex-1 bg-black/60 border border-white/10 rounded-2xl p-5 text-white text-[12px] outline-none" />
                  <button onClick={handleAddKey} className="bg-white text-slate-950 px-10 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all">Forger</button>
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {accounts.map(acc => (
                 <div key={acc.id} className="bg-white/[0.03] p-6 rounded-3xl border border-white/5 flex items-center justify-between group">
                    <div>
                       <p className={`text-[13px] font-black ${acc.role === 'SUPER_MASTER' ? 'text-cyan-400' : 'text-white'}`}>{acc.username}</p>
                       <p className="text-[8px] text-white/30 uppercase font-black">{acc.role}</p>
                    </div>
                    {acc.role !== 'SUPER_MASTER' && (
                      <button onClick={() => handleRemoveKey(acc.id)} className="bg-red-500/10 text-red-500 p-4 rounded-2xl hover:bg-red-500 hover:text-white transition-all">
                         <i className="fas fa-trash-alt text-[10px]"></i>
                      </button>
                    )}
                 </div>
               ))}
            </div>
          </div>
        )}

        {activeTab === 'spy' && (
          <div className="space-y-8 animate-in">
             <div className="bg-black/40 rounded-[2rem] border border-white/5 p-6 overflow-x-auto">
                <table className="w-full text-left">
                    <thead>
                        <tr className="text-[8px] uppercase font-black text-white/20 tracking-[0.4em] border-b border-white/10">
                            <th className="pb-4">Identité</th>
                            <th className="pb-4">Action</th>
                            <th className="pb-4 text-right">Instant</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/[0.04]">
                        {activities.map(act => (
                            <tr key={act.id}>
                                <td className="py-4 text-[10px] text-white/80 font-bold">{act.email || 'Anonyme'}</td>
                                <td className="py-4 text-[9px] text-cyan-400 italic">{act.fileName || 'Navigation'}</td>
                                <td className="py-4 text-[8px] text-white/10 font-mono text-right">{act.timestamp}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
             </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-3 animate-in">
            {storageService.getLogs().map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-xl text-[10px] font-mono border border-white/5 flex gap-4">
                   <span className="text-white/10">[{log.timestamp}]</span>
                   <span className="text-cyan-400 font-black uppercase">{log.action}</span>
                   <span className="text-white/60">"{log.details}"</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, VisitorActivity, AdminAccount } from '../types.ts';
import { GOOGLE_SHEET_ID } from '../constants.ts';
import DocumentCard from './DocumentCard.tsx';

interface AdminDashboardProps {
  categories: Category[];
  documents: Document[];
  currentAdmin: AdminAccount | null;
  onRefresh?: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ categories, documents, currentAdmin, onRefresh }) => {
  const [activeTab, setActiveTab] = useState<'status' | 'architect' | 'spy' | 'keys' | 'logs'>('status');
  const [activities, setActivities] = useState<VisitorActivity[]>([]);
  const [accounts, setAccounts] = useState<AdminAccount[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);

  // Wizard state (Step-by-step logic)
  const [publishStep, setPublishStep] = useState(0);
  const [mode, setMode] = useState<'category' | 'document'>('document');
  const [isPublished, setIsPublished] = useState(false);

  // For keys management
  const [newKeyName, setNewKeyName] = useState('');

  // Form states
  const [parentSelection, setParentSelection] = useState<string>('root');
  const [newItem, setNewItem] = useState({
    name: '',
    icon: '📁',
    title: '',
    description: '',
    url: '',
    size: '1.0 MB',
    tags: 'Cours|Révision'
  });

  const [generatedRow, setGeneratedRow] = useState<string>('');

  useEffect(() => {
    setActivities(storageService.getVisitorActivities());
    setAccounts(storageService.getAccounts());
  }, []);

  const handleManualSync = async () => {
    setIsSyncing(true);
    if (onRefresh) await onRefresh();
    setIsSyncing(false);
  };

  const handleAddKey = () => {
    if (!newKeyName) return;
    storageService.addAccount(newKeyName, 'MASTER');
    setAccounts(storageService.getAccounts());
    setNewKeyName('');
    storageService.addLog('ACCOUNT', `Nouvelle clé créée pour ${newKeyName}`);
  };

  const handleRemoveKey = (id: string) => {
    if (id === '0') return; 
    storageService.removeAccount(id);
    setAccounts(storageService.getAccounts());
    storageService.addLog('ACCOUNT', `Clé révoquée (ID: ${id})`);
  };

  const handleFinalPublish = () => {
    const id = Math.random().toString(36).substr(2, 9);
    const parentId = parentSelection === 'root' ? '' : parentSelection;

    if (mode === 'category') {
      setGeneratedRow(`${id},"${newItem.name}","${parentId}","${newItem.icon}"`);
    } else {
      const date = new Date().toISOString();
      setGeneratedRow(`${id},"${newItem.title}","${newItem.description}","${parentId}","${newItem.url.trim()}","pdf","${newItem.tags}",0,"${date}","${newItem.size}"`);
    }
    setIsPublished(true);
    storageService.addLog('UPLOAD', `Préparation de la publication : ${mode === 'category' ? newItem.name : newItem.title}`);
  };

  const resetWizard = () => {
    setPublishStep(0);
    setIsPublished(false);
    setGeneratedRow('');
    setNewItem({
      name: '',
      icon: '📁',
      title: '',
      description: '',
      url: '',
      size: '1.0 MB',
      tags: 'Cours|Révision'
    });
  };

  // Virtual document for preview
  const previewDoc: Document = {
    id: 'preview',
    title: newItem.title || 'Titre en attente',
    description: newItem.description || 'Description en attente',
    categoryId: parentSelection,
    fileUrl: newItem.url,
    fileType: 'pdf',
    tags: newItem.tags.split('|'),
    downloads: 0,
    dateAdded: new Date().toISOString(),
    size: newItem.size
  };

  return (
    <div className="bg-slate-950/40 rounded-[2rem] md:rounded-[3rem] border border-white/5 overflow-hidden backdrop-blur-3xl shadow-2xl flex flex-col min-h-[600px]">
      {/* Navigation Tabs */}
      <div className="flex bg-black/60 overflow-x-auto no-scrollbar border-b border-white/10">
        {[
          { id: 'status', label: 'État Cloud', icon: '☁️' },
          { id: 'architect', label: 'Architecte', icon: '🏛️' },
          { id: 'spy', label: 'Espionnage', icon: '👁️' },
          ...(currentAdmin?.role === 'SUPER_MASTER' ? [{ id: 'keys', label: 'Clés Stellaires', icon: '🔑' }] : []),
          { id: 'logs', label: 'Système', icon: '📟' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => { setActiveTab(tab.id as any); resetWizard(); }}
            className={`flex-1 py-6 px-8 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap flex items-center justify-center gap-3 ${
              activeTab === tab.id ? 'border-cyan-500 bg-cyan-500/5 text-white' : 'border-transparent text-white/30 hover:text-white'
            }`}
          >
            <span className="text-sm">{tab.icon}</span>
            {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-12 flex-1 flex flex-col overflow-y-auto max-h-[700px] no-scrollbar">
        {activeTab === 'status' && (
          <div className="space-y-8 animate-in">
            <div className="bg-gradient-to-br from-slate-900 to-black p-10 rounded-[2.5rem] border border-white/10 shadow-xl">
               <h3 className="text-xl font-black text-white uppercase italic mb-6">Noyau de Données</h3>
               <p className="text-white/40 text-[11px] uppercase font-bold tracking-[0.3em] mb-8 leading-loose">
                 Connexion à la Matrice : <span className="text-cyan-400 font-mono break-all">{GOOGLE_SHEET_ID}</span>
               </p>
               <div className="flex flex-col sm:flex-row gap-4">
                  <button onClick={() => window.open(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/edit`, '_blank')} className="flex-1 bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-lg">Ouvrir la Matrice Sheets</button>
                  <button onClick={handleManualSync} disabled={isSyncing} className="flex-1 bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-500 hover:text-slate-950 transition-all">{isSyncing ? 'Synchronisation...' : 'Forcer la Mise à Jour'}</button>
               </div>
            </div>
          </div>
        )}

        {activeTab === 'architect' && (
          <div className="max-w-4xl mx-auto w-full space-y-12 animate-in py-6">
            <div className="text-center space-y-4">
              <h3 className="text-2xl font-black text-white uppercase italic tracking-tighter">Assistant de Publication Polaris</h3>
              {!isPublished && (
                <p className="text-[10px] text-white/30 font-black uppercase tracking-[0.5em]">Étape {publishStep + 1} / {mode === 'document' ? 6 : 4}</p>
              )}
            </div>

            <div className="bg-white/[0.03] border border-white/10 rounded-[3rem] p-10 md:p-16 relative overflow-hidden">
               {/* Progress Bar */}
               {!isPublished && (
                 <div className="absolute top-0 left-0 h-1 bg-cyan-500 transition-all duration-700" style={{ width: `${((publishStep + 1) / (mode === 'document' ? 6 : 4)) * 100}%` }}></div>
               )}

               {isPublished ? (
                 <div className="space-y-10 animate-in text-center">
                    <div className="w-24 h-24 bg-emerald-500/20 rounded-full flex items-center justify-center mx-auto border border-emerald-500/30 shadow-[0_0_50px_rgba(16,185,129,0.2)]">
                       <i className="fas fa-check-circle text-emerald-400 text-4xl"></i>
                    </div>
                    <div className="space-y-2">
                       <h4 className="text-white font-black uppercase tracking-[0.3em] text-2xl italic">PUBLIÉ DANS POLARIS</h4>
                       <p className="text-[10px] text-white/40 font-black uppercase tracking-widest leading-loose">
                         Le signal a été transmis. Pour finaliser l'ancrage permanent,<br/>copiez la ligne ci-dessous dans la feuille Google Sheets correspondante.
                       </p>
                    </div>

                    <div className="bg-black/80 rounded-3xl p-8 border border-cyan-500/30 font-mono text-cyan-400 break-all select-all text-[12px] shadow-2xl relative">
                        <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-slate-900 px-4 py-1 rounded-full text-[8px] font-black uppercase text-white/40 border border-white/10">Ligne de Matrice Générée</div>
                        {generatedRow}
                    </div>

                    <div className="flex flex-col sm:flex-row gap-4 pt-6">
                       <button onClick={resetWizard} className="flex-1 bg-white/5 text-white/60 py-5 rounded-2xl text-[10px] font-black uppercase border border-white/10 hover:bg-white/10 transition-all">Nouvelle Publication</button>
                       <button onClick={() => window.open(`https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/edit`, '_blank')} className="flex-[2] bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-lg">Ouvrir Sheets pour coller</button>
                    </div>
                 </div>
               ) : (
                 <div className="space-y-10">
                   {/* Step 0: Choice */}
                   {publishStep === 0 && (
                     <div className="space-y-10 animate-in">
                       <p className="text-center text-white/60 font-medium italic">"Quel savoir souhaitez-vous matérialiser aujourd'hui ?"</p>
                       <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                         <button onClick={() => { setMode('document'); setPublishStep(1); }} className="bg-indigo-500/10 border border-indigo-500/30 p-12 rounded-[2.5rem] hover:bg-indigo-500 transition-all group">
                            <span className="block text-4xl mb-4 group-hover:scale-125 transition-transform duration-500">📄</span>
                            <span className="block text-white font-black uppercase tracking-widest text-[11px]">Nouveau Document</span>
                         </button>
                         <button onClick={() => { setMode('category'); setPublishStep(1); }} className="bg-cyan-500/10 border border-cyan-500/30 p-12 rounded-[2.5rem] hover:bg-cyan-500 transition-all group">
                            <span className="block text-4xl mb-4 group-hover:scale-125 transition-transform duration-500">📁</span>
                            <span className="block text-white font-black uppercase tracking-widest text-[11px]">Sous-Catégorie</span>
                         </button>
                       </div>
                     </div>
                   )}

                   {/* DOCUMENT FLOW */}
                   {mode === 'document' && publishStep === 1 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 1 : Lien du Savoir (Google Drive)</h4>
                        <button onClick={() => window.open('https://drive.google.com', '_blank')} className="w-full bg-white/5 text-indigo-400 py-3 rounded-xl text-[9px] font-black uppercase border border-white/10 hover:bg-white/10 transition-all">Accéder à Google Drive</button>
                        <input type="text" autoFocus placeholder="Collez le lien de partage ici..." value={newItem.url} onChange={e => setNewItem({...newItem, url: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center shadow-inner" />
                        <button onClick={() => newItem.url && setPublishStep(2)} disabled={!newItem.url} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 disabled:opacity-20 transition-all shadow-xl">OK - Valider le Lien</button>
                        <button onClick={resetWizard} className="w-full text-white/20 text-[9px] uppercase font-black">Annuler</button>
                      </div>
                   )}

                   {mode === 'document' && publishStep === 2 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 2 : Nom de l'Archive</h4>
                        <input type="text" autoFocus placeholder="Titre du document..." value={newItem.title} onChange={e => setNewItem({...newItem, title: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center shadow-inner" />
                        <button onClick={() => newItem.title && setPublishStep(3)} disabled={!newItem.title} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 disabled:opacity-20 transition-all shadow-xl">OK - Valider le Titre</button>
                        <button onClick={() => setPublishStep(1)} className="w-full text-white/20 text-[9px] uppercase font-black">Retour</button>
                      </div>
                   )}

                   {mode === 'document' && publishStep === 3 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 3 : Essence du Contenu</h4>
                        <textarea autoFocus placeholder="Décrivez brièvement ce document..." value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} className="w-full h-32 bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium resize-none shadow-inner" />
                        <button onClick={() => newItem.description && setPublishStep(4)} disabled={!newItem.description} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 disabled:opacity-20 transition-all shadow-xl">OK - Valider la Description</button>
                        <button onClick={() => setPublishStep(2)} className="w-full text-white/20 text-[9px] uppercase font-black">Retour</button>
                      </div>
                   )}

                   {mode === 'document' && publishStep === 4 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape 4 : Secteur d'Ancrage</h4>
                        <select value={parentSelection} onChange={(e) => setParentSelection(e.target.value)} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 text-center cursor-pointer appearance-none shadow-inner">
                          <option value="root">Racine Polaris</option>
                          {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <button onClick={() => setPublishStep(5)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-xl">OK - Valider la Catégorie</button>
                        <button onClick={() => setPublishStep(3)} className="w-full text-white/20 text-[9px] uppercase font-black">Retour</button>
                      </div>
                   )}

                   {mode === 'document' && publishStep === 5 && (
                      <div className="space-y-10 animate-in">
                        <div className="space-y-4">
                           <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Étape Finale : Prévisualisation</h4>
                           <p className="text-center text-[10px] text-white/40 uppercase font-black italic">"Le document apparaîtra ainsi dans le Palais"</p>
                        </div>

                        <div className="max-w-[320px] mx-auto">
                           <DocumentCard doc={previewDoc} onDownload={() => {}} />
                        </div>

                        <div className="bg-black/40 p-6 rounded-3xl border border-white/5 space-y-4">
                           <div className="flex justify-between items-center text-[11px] font-black uppercase tracking-widest">
                              <span className="text-white/20">Taille :</span>
                              <input type="text" value={newItem.size} onChange={e => setNewItem({...newItem, size: e.target.value})} className="bg-transparent text-right text-cyan-400 outline-none w-24" />
                           </div>
                        </div>

                        <button onClick={handleFinalPublish} className="w-full bg-cyan-500 text-slate-950 py-6 rounded-[2rem] text-[12px] font-black uppercase tracking-[0.5em] hover:bg-white transition-all shadow-[0_0_40px_rgba(0,212,255,0.3)]">PUBLIER DANS LE PALAIS</button>
                        <button onClick={() => setPublishStep(4)} className="w-full text-white/20 text-[9px] uppercase font-black tracking-widest">Retour pour modification</button>
                      </div>
                   )}

                   {/* CATEGORY FLOW */}
                   {mode === 'category' && publishStep === 1 && (
                      <div className="space-y-8 animate-in">
                        <h4 className="text-white text-center font-black uppercase tracking-widest text-sm">Nom de la Constellation</h4>
                        <input type="text" autoFocus placeholder="Titre de la catégorie..." value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[13px] outline-none focus:border-cyan-400 font-medium text-center shadow-inner" />
                        <button onClick={() => newItem.name && setPublishStep(2)} disabled={!newItem.name} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-xl">OK - Valider le Nom</button>
                        <button onClick={resetWizard} className="w-full text-white/20 text-[9px] uppercase font-black">Annuler</button>
                      </div>
                   )}

                   {mode === 'category' && publishStep === 2 && (
                      <div className="space-y-8 animate-in">
